const a = [
  {"id":92,"text":"Lesion of the dorsal column results in which of the following?","explanation":null,"reference":"Sensory ataxia - an overview | sciencedirect topics. Accessed March 30, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/sensory-ataxia","responses":[{"text":"Loss of temperature sensation","correct":false,"visible":false},{"text":"Motor ataxia","correct":false,"visible":false},{"text":"Sensory ataxia","correct":true,"visible":false},{"text":"Loss of pain sensations","correct":false,"visible":false},{"text":"Apraxia","correct":false,"visible":false}]},{"id":93,"text":"Where does the superior sagittal sinus drain into?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 423.","responses":[{"text":"Ethmoidal sinus","correct":false,"visible":false},{"text":"Longitudinal sinus","correct":false,"visible":false},{"text":"Right transverse sinus","correct":true,"visible":false},{"text":"Straight sinus","correct":false,"visible":false},{"text":"Sinusoidal sinus","correct":false,"visible":false}]},{"id":116,"text":"Which of the following is an autoimmune disease affecting the nicotinic acetylcholine receptors?","explanation":null,"reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 115.","responses":[{"text":"Duchenne muscular dystrophy (DMD)","correct":false,"visible":false},{"text":"Myasthenia gravis","correct":true,"visible":false},{"text":"Amyotrophic lateral sclerosis","correct":false,"visible":false},{"text":"Guillain-Barré syndrome","correct":false,"visible":false},{"text":"Multiple sclerosis","correct":false,"visible":false}]},{"id":118,"text":"Serotonin or 5-hydroxytryptamine is synthesized from which of the following?","explanation":null,"reference":"Bakshi A, Tadi P. Biochemistry, serotonin. In: StatPearls. StatPearls Publishing; 2022. Accessed March 25, 2022. http://www.ncbi.nlm.nih.gov/books/NBK560856/","responses":[{"text":"Tri-carboxylic acid","correct":false,"visible":false},{"text":"Taurine","correct":false,"visible":false},{"text":"Tri-acyl glycerol","correct":false,"visible":false},{"text":"Tyrosine","correct":false,"visible":false},{"text":"Tryptophan","correct":true,"visible":false}]},{"id":157,"text":"What does a 'cobweb' appearance of the CSF indicate?","explanation":null,"reference":"Vinnard C, King L, Munsiff S, et al. Long-term mortality of patients with tuberculous meningitis in new york city: a cohort study. Clinical Infectious Diseases. Published December 7, 2016. Accessed March 25, 2022. https://academic.oup.com/cid/article-lookup/doi/10.1093/cid/ciw763","responses":[{"text":"Tuberculous meningitis","correct":true,"visible":false},{"text":"Viral meningitis","correct":false,"visible":false},{"text":"Viral encephalitis","correct":false,"visible":false},{"text":"Neurosyphilis","correct":false,"visible":false},{"text":"Acute pyogenic meningitis","correct":false,"visible":false}]},{"id":241,"text":"Which one of the following forms the blood-brain barrier?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 453.","responses":[{"text":"Hepatocytes","correct":false,"visible":false},{"text":"Neurons","correct":false,"visible":false},{"text":"Osteocytes","correct":false,"visible":false},{"text":"Smooth muscle cells","correct":false,"visible":false},{"text":"Astrocytes","correct":true,"visible":false}]},{"id":262,"text":"What is the biologically active amine form of phenylalanine?","explanation":null,"reference":"Ferrier DR. Lippincott’s Illustrated Reviews: Biochemistry. 7th ed. Wolters Kluwer; 2017: 285.","responses":[{"text":"Tyrosine","correct":false,"visible":false},{"text":"Valine","correct":false,"visible":false},{"text":"Tryptamine","correct":false,"visible":false},{"text":"Taurine","correct":false,"visible":false},{"text":"Dopamine","correct":true,"visible":false}]},{"id":391,"text":"Which nucleus of the hypothalamus is involved in the regulation of thirst and hunger?","explanation":"The **lateral nucleus** of the hypothalamus is involved in the regulation of both thirst and hunger.\r\n\r\n1. **Thirst Regulation:** The lateral hypothalamic area contains neurons that are responsible for triggering thirst sensations. When the body's water levels are low or when there is an increase in the concentration of solutes in the blood, these neurons are activated, leading to the sensation of thirst. Thirst is an essential mechanism that helps maintain proper water balance in the body.\r\n\r\n2. **Hunger Regulation:** The lateral hypothalamic area also plays a significant role in the regulation of hunger. Neurons in this region are involved in stimulating appetite and food intake. When these neurons are activated, it leads to feelings of hunger and an increased desire to eat.","reference":"Snell RS. Clinical Neuroanatomy. 7th ed. Wolters Kluwer Health/Lippincott Williams \u0026 Wilkins; 2010: 390.","responses":[{"text":"Paraventricular nucleus","correct":false,"visible":false},{"text":"Lateral nucleus","correct":true,"visible":false},{"text":"Supraoptic nucleus","correct":false,"visible":false},{"text":"Suprachiasmatic nucleus","correct":false,"visible":false},{"text":"Ventromedial nucleus","correct":false,"visible":false}]},{"id":402,"text":"In a T2WI section magnetic resonance imaging (MRI), the cerebrospinal fluid appears as which of the following?","explanation":null,"reference":"Mri  basics. Accessed March 31, 2022. https://case.edu/med/neurology/NR/MRI%20Basics.htm","responses":[{"text":"Bright","correct":true,"visible":false},{"text":"Grey","correct":false,"visible":false},{"text":"Jet black","correct":false,"visible":false},{"text":"Dark","correct":false,"visible":false},{"text":"Black","correct":false,"visible":false}]},{"id":427,"text":"Which of the following happens in Parkinson's disease?","explanation":null,"reference":"Zafar S, Yaddanapudi SS. Parkinson disease. In: StatPearls. StatPearls Publishing; 2022. Accessed March 30, 2022. http://www.ncbi.nlm.nih.gov/books/NBK470193/","responses":[{"text":"D3 receptors are destroyed","correct":false,"visible":false},{"text":"D1 receptors are destroyed","correct":false,"visible":false},{"text":"D2 receptors are destroyed","correct":false,"visible":false},{"text":"Dopaminergic neurons are destroyed","correct":true,"visible":false},{"text":"All of these","correct":false,"visible":false}]},{"id":9693,"text":"Which of the following waves are seen when a person is awake and is alert?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 756.","responses":[{"text":"Theta waves","correct":false,"visible":false},{"text":"Delta waves","correct":false,"visible":false},{"text":"Beta waves","correct":true,"visible":false},{"text":"Low voltage spindles","correct":false,"visible":false},{"text":"Alpha waves","correct":false,"visible":false}]},{"id":9697,"text":"Association fibers are the nerve fibers that connect different regions within the same hemisphere. Which of the following is categorized as the association fiber?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 264.","responses":[{"text":"Fornix","correct":false,"visible":false},{"text":"Internal capsule","correct":false,"visible":false},{"text":"Corpus callosum","correct":false,"visible":false},{"text":"Cingulum","correct":true,"visible":false},{"text":"External capsule","correct":false,"visible":false}]},{"id":9803,"text":"To which of the following classes do the endorphins belong?","explanation":null,"reference":"Endorphins - an overview | sciencedirect topics. Accessed December 10, 2022. https://www.sciencedirect.com/topics/neuroscience/endorphins","responses":[{"text":"Amine","correct":false,"visible":false},{"text":"Steroids","correct":false,"visible":false},{"text":"Catecholamines","correct":false,"visible":false},{"text":"Monoamine","correct":false,"visible":false},{"text":"Peptide","correct":true,"visible":false}]},{"id":9804,"text":"Which of the following is associated with increased dopamine levels?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 306.","responses":[{"text":"Global aphasia without hemiparesis","correct":false,"visible":false},{"text":"Schizophrenia","correct":true,"visible":false},{"text":"Parkinson's disease","correct":false,"visible":false},{"text":"Agnosia","correct":false,"visible":false},{"text":"Alzheimer's disease","correct":false,"visible":false}]},{"id":9805,"text":"Which of the following is not derived from tyrosine?","explanation":null,"reference":"Nussey S, Whitehead S. Principles of Endocrinology. BIOS Scientific Publishers; 2001. Accessed December 10, 2022. https://www.ncbi.nlm.nih.gov/books/NBK20/","responses":[{"text":"Serotonin","correct":true,"visible":false},{"text":"Epinephrine","correct":false,"visible":false},{"text":"Dopamine","correct":false,"visible":false},{"text":"Adrenaline","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false}]},{"id":10914,"text":"Acetylcholine increases the permeability of which of the following ions when it binds to nicotinic receptors at the postsynaptic neuron?","explanation":null,"reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 91.","responses":[{"text":"Sodium","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Potassium","correct":false,"visible":false},{"text":"Calcium","correct":false,"visible":false},{"text":"Magnesium","correct":false,"visible":false}]},{"id":10915,"text":"Damage to which structure causes Parkinson's disease?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 315.","responses":[{"text":"Globus pallidus","correct":false,"visible":false},{"text":"Substantia nigra","correct":true,"visible":false},{"text":"Subthalamus","correct":false,"visible":false},{"text":"Putamen","correct":false,"visible":false},{"text":"Caudate","correct":false,"visible":false}]},{"id":10918,"text":"Hemiballismus is caused due to damage to which of the following structures?","explanation":null,"reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 315.","responses":[{"text":"Putamen","correct":false,"visible":false},{"text":"Globus pallidus","correct":false,"visible":false},{"text":"Corpus striatum","correct":false,"visible":false},{"text":"Subthalamus","correct":true,"visible":false},{"text":"Caudate","correct":false,"visible":false}]},{"id":12566,"text":"The posterior grey horn of the spinal cord develops from which of the following?","explanation":"The posterior gray horn of the spinal cord, which contains sensory neurons and processes sensory information, develops from the **alar plate** during embryonic development.\r\n\r\nIn the early stages of spinal cord development, the neural tube undergoes patterning to give rise to different regions and structures. The neural tube is divided into distinct plates: the alar plate and the basal plate. The alar plate is primarily involved in the development of sensory structures, while the basal plate is associated with motor functions.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 489.","responses":[{"text":"Floor plate","correct":false,"visible":false},{"text":"Roof plate","correct":false,"visible":false},{"text":"Sulcus limitans","correct":false,"visible":false},{"text":"Basal plate","correct":false,"visible":false},{"text":"Alar plate","correct":true,"visible":false}]},{"id":12567,"text":"Which of the following glial cells is not derived from the neuroectoderm?","explanation":"**Microglial cells** are the resident immune cells of the central nervous system (CNS). They have a crucial role in the immune defense of the CNS and are involved in responding to injury, infection, or inflammation within the brain and spinal cord. Unlike other glial cells that originate from the neuroectoderm, microglial cells arise from a different lineage, specifically from the **mesodermal** origin. During embryogenesis, they are derived from myeloid progenitor cells, which are part of the immune system's lineage.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 58.","responses":[{"text":"Ependymal cells","correct":false,"visible":false},{"text":"Microglial cells","correct":true,"visible":false},{"text":"Schwann cells","correct":false,"visible":false},{"text":"Oligodendrocytes","correct":false,"visible":false},{"text":"Astrocytes","correct":false,"visible":false}]},{"id":12572,"text":"Which of the following thalamic nuclei receives sensory afferents from the face and mouth?","explanation":"The thalamic nucleus that receives sensory afferents from the face and mouth is the **ventro-posterior medial nucleus** (VPM).\r\n\r\nThe VPM nucleus is a key relay station in the thalamus responsible for processing somatosensory information from the face and mouth. The sensory information from the face and mouth is carried by the trigeminal nerve (cranial nerve V) and its branches. These sensory fibers synapse in the VPM nucleus before onward transmission to the somatosensory cortex, where the brain perceives and interprets tactile and sensory input from the facial and oral regions.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 366.","responses":[{"text":"Ventro-posterior lateral","correct":false,"visible":false},{"text":"Ventral anterior","correct":false,"visible":false},{"text":"Ventro-posterior medial","correct":true,"visible":false},{"text":"Lateral dorsal","correct":false,"visible":false},{"text":"Pulvinar","correct":false,"visible":false}]},{"id":12642,"text":"A 60-year-old hypertensive male was taken to the emergency department with complaints of sudden onset of nausea and vomiting. The examination revealed slurred speech and dysmetria on finger-to-nose test on the left side. However, his gait was normal. In which of the following areas lesion has occurred?","explanation":"The patient's presentation of sudden onset nausea, vomiting, slurred speech, and dysmetria on the finger-to-nose test on the left side suggests dysfunction in the **left cerebellar hemisphere.** The cerebellum plays a crucial role in coordinating and regulating voluntary movements, including motor control, balance, and coordination.\r\n\r\nThe specific clinical signs, such as slurred speech and dysmetria (inability to control the range of movement during fine tasks), are indicative of cerebellar dysfunction. The left cerebellar hemisphere primarily influences the coordination of movements on the ipsilateral (left) side of the body.\r\n\r\nNotably, the patient's normal gait indicates that the lesion is likely confined to the cerebellar hemisphere rather than involving the flocculonodular lobe or deeper structures like the fastigial or vestibular nuclei.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 238, 240-243.","responses":[{"text":"Right flocculonodular lobe","correct":false,"visible":false},{"text":"Right cerebellar hemisphere","correct":false,"visible":false},{"text":"Left cerebellar hemisphere","correct":true,"visible":false},{"text":"Fastigial nucleus","correct":false,"visible":false},{"text":"Vestibular nucleus","correct":false,"visible":false}]},{"id":12643,"text":"A radiologist, while reading the computed tomography scan, noticed a jugular tubercle grooved by IX, X, and XI cranial nerves. This tubercle is part of which of the following bones?","explanation":"The jugular tubercle, which is grooved by the IX (glossopharyngeal), X (vagus), and XI (accessory) cranial nerves, is part of the **Occipital bone**. This tubercle is a prominence on the occipital bone and is located at the posterior part of the jugular foramen, an opening that allows for the passage of these cranial nerves and the internal jugular vein. The occipital bone is situated at the lower and back part of the skull and forms a significant portion of the cranial base.","reference":"Drake RL. Gray’s Anatomy for Students. 4th ed. Elsevier; 2020: 857.","responses":[{"text":"Temporal bone","correct":false,"visible":false},{"text":"Ethmoid bone","correct":false,"visible":false},{"text":"Parietal bone","correct":false,"visible":false},{"text":"Occipital bone","correct":true,"visible":false},{"text":"Sphenoid bone","correct":false,"visible":false}]},{"id":12646,"text":"An 80-year-old male came to the hospital with a head injury due to a bad fall. He had a stylomastoid fracture. Which of the following nerves is most likely to be damaged?","explanation":"The stylomastoid foramen is an important anatomical structure located in the temporal bone, specifically at the junction between the styloid process and mastoid process. It serves as the exit point for the **facial nerve** (Cranial Nerve VII) as it exits the skull and enters the facial region.\r\n\r\nDamage to the Facial nerve can result in various neurological deficits, including facial weakness or paralysis on the affected side, altered taste sensation in the anterior two-thirds of the tongue, and difficulty with facial expressions, among other symptoms.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 338.","responses":[{"text":"Facial nerve","correct":true,"visible":false},{"text":"Optic nerve","correct":false,"visible":false},{"text":"Vestibulocochlear nerve","correct":false,"visible":false},{"text":"Ophthalmic nerve","correct":false,"visible":false},{"text":"Olfactory nerve","correct":false,"visible":false}]},{"id":12648,"text":"A 45-year-old female is in recovery from a stroke. She is found to have difficulty in speech. She can write the words and can understand their meanings but is unable to produce words. Where is the cerebral cortical area responsible for the above-stated condition located?","explanation":"The specific region within the **Inferior Frontal Gyrus** is known as **Broca's Area**, which plays a crucial role in language production. Damage or dysfunction in Broca's Area can result in a condition called **Broca's Aphasia** or **Non-fluent Aphasia**. In individuals with Broca's Aphasia, comprehension of language remains intact, as observed in this patient. However, the ability to form coherent and fluent speech is impaired.\r\n\r\nPatients with Broca's Aphasia often struggle to articulate words and sentences, and their speech may be characterized by short and grammatically simple phrases. They may experience frustration due to their difficulty in expressing themselves verbally, even though their understanding of language remains relatively intact.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 284.","responses":[{"text":"Inferior frontal gyrus","correct":true,"visible":false},{"text":"Superior frontal gyrus","correct":false,"visible":false},{"text":"Middle temporal gyrus","correct":false,"visible":false},{"text":"Superior temporal gyrus","correct":false,"visible":false},{"text":"Middle frontal gyrus","correct":false,"visible":false}]},{"id":12653,"text":"What are the commissural fibers associated with the olfactory pathway called?","explanation":"The olfactory system plays a crucial role in the sense of smell, and it involves the detection and processing of various odors. The olfactory bulbs, which are part of this system, are located on the undersurface of the frontal lobes of the brain. The **anterior commissure** serves as a connecting bridge between the two olfactory bulbs, allowing for the exchange of olfactory information between the left and right hemispheres of the brain.\r\n\r\nThese commissural fibers enable the integration of olfactory input from both sides of the nasal passages, contributing to a unified perception of smell.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 327.","responses":[{"text":"Hippocampal commissure","correct":false,"visible":false},{"text":"Corpus callosum","correct":false,"visible":false},{"text":"Habenular commissure","correct":false,"visible":false},{"text":"Posterior commissure","correct":false,"visible":false},{"text":"Anterior commissure","correct":true,"visible":false}]},{"id":12655,"text":"Which one of the following arteries supplies the medulla oblongata?","explanation":"The artery that supplies the medulla oblongata is the **Posterior Inferior Cerebellar Artery (PICA)**.\r\n\r\nThe medulla oblongata is a critical part of the brainstem, responsible for various vital functions such as regulating heart rate, blood pressure, respiration, and other autonomic functions. It also serves as a relay station for sensory and motor pathways traveling between the spinal cord and the higher brain centers.\r\n\r\nThe PICA is one of the three branches of the vertebral artery, and it plays a crucial role in supplying blood to the posterior aspect of the brainstem, including the medulla oblongata.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 466.","responses":[{"text":"Anterior communicating artery","correct":false,"visible":false},{"text":"Basilar artery","correct":false,"visible":false},{"text":"Superior cerebellar artery","correct":false,"visible":false},{"text":"Middle cerebral artery","correct":false,"visible":false},{"text":"Posterior inferior cerebellar artery","correct":true,"visible":false}]},{"id":12665,"text":"Which of the following arteries supply the corpus striatum and internal capsule?","explanation":"The **middle cerebral artery** is primarily responsible for supplying blood to the corpus striatum and internal capsule. The middle cerebral artery provides blood to large portions of the lateral surface of the brain, including areas involved in motor and sensory functions.\r\n\r\nThe corpus striatum, which includes the caudate nucleus and the putamen, and the internal capsule, a vital pathway for motor and sensory fibers, are both located in regions supplied by the middle cerebral artery. This artery's branches penetrate deeply into the brain tissue, delivering oxygenated blood to these critical structures.\r\n\r\nThe posterior inferior cerebellar artery primarily supplies parts of the cerebellum and medulla, the posterior cerebral artery supplies the occipital lobe and parts of the temporal lobe, the superior cerebellar artery also supplies the cerebellum, and the anterior communicating artery is part of the circle of Willis and connects the two anterior cerebral arteries but does not directly supply the corpus striatum or internal capsule.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 465.","responses":[{"text":"Posterior cerebral artery","correct":false,"visible":false},{"text":"Posterior inferior cerebellar artery","correct":false,"visible":false},{"text":"Middle cerebral artery","correct":true,"visible":false},{"text":"Anterior communicating artery","correct":false,"visible":false},{"text":"Superior cerebellar artery","correct":false,"visible":false}]},{"id":12666,"text":"Auditory fibers run in the lateral lemniscus terminate in which of the following structures?","explanation":"Auditory fibers that run in the **lateral lemniscus** terminate in the **inferior colliculus**. \r\n\r\nAs sound information travels from the ear to the brain for processing, it undergoes a series of relay stations. The lateral lemniscus is one of these pathways within the auditory system, and it carries auditory information from the cochlear nuclei to the superior olivary complex and then on to the inferior colliculus. \r\n\r\nThe **inferior colliculus** is a significant midbrain structure involved in auditory processing. It receives input from both ears and plays a crucial role in sound localization, integrating auditory information, and coordinating reflexive responses to sound, such as the startle reflex.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 209-210.","responses":[{"text":"Crus cerebri","correct":false,"visible":false},{"text":"Superior colliculus","correct":false,"visible":false},{"text":"Lateral geniculate nucleus","correct":false,"visible":false},{"text":"Inferior colliculus","correct":true,"visible":false},{"text":"Medial leminiscus","correct":false,"visible":false}]},{"id":12667,"text":"Which of the following is present anterior to the interventricular foramen?","explanation":"The fornix is a prominent structure in the limbic system of the brain and plays a vital role in memory and emotion processing. It is a C-shaped bundle of nerve fibers that connects various limbic system structures, including the hippocampus and the mammillary bodies.\r\n\r\nIn the context of the interventricular foramen, which is also known as the foramen of Monro, the **anterior column of the fornix** is situated anteriorly. The interventricular foramen connects the lateral ventricles of the brain, allowing cerebrospinal fluid (CSF) to flow between them.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 304.","responses":[{"text":"Anterior column of fornix","correct":true,"visible":false},{"text":"Septum pellucidum","correct":false,"visible":false},{"text":"Posterior end of thalamus","correct":false,"visible":false},{"text":"Anterior commissure","correct":false,"visible":false},{"text":"Posterior column of fornix","correct":false,"visible":false}]},{"id":12668,"text":"Gray rami communicans are derived from which of the following?","explanation":"Gray rami communicans are derived from the **paravertebral ganglion**. The gray rami communicans are small nerve branches that connect the paravertebral ganglia of the sympathetic trunk to the spinal nerves. Each gray ramus communicans carries postganglionic sympathetic fibers from a paravertebral ganglion to a spinal nerve.\r\n\r\nThese fibers are unmyelinated, which gives the gray rami their characteristic color, in contrast to the myelinated fibers of the white rami communicans. The paravertebral ganglia, part of the sympathetic chain, are aligned vertically along the spine.\r\n\r\nThe function of these gray rami is to distribute sympathetic nerve fibers to various parts of the body, including the limbs and the body wall. They are responsible for carrying sympathetic impulses that regulate functions such as blood vessel constriction, sweat secretion, and piloerection (hair standing on end).\r\n\r\nThe posterior root ganglion contains sensory neuron cell bodies, the lateral horn of the spinal cord contains cell bodies of preganglionic sympathetic neurons, the anterior horn of the spinal cord contains motor neuron cell bodies, and the adjacent ganglion of the sympathetic trunk refers to another ganglion in the sympathetic chain.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 388.","responses":[{"text":"Anterior horn of spinal cord","correct":false,"visible":false},{"text":"Adjacent ganglion of sympathetic trunk","correct":false,"visible":false},{"text":"Lateral horn of spinal cord","correct":false,"visible":false},{"text":"Paravertebral ganglion","correct":true,"visible":false},{"text":"Posterior root ganglion","correct":false,"visible":false}]},{"id":12669,"text":"Which of the following can be caused by an infarction of the genu of the internal capsule?","explanation":"The internal capsule is a white matter tract in the brain that serves as a major highway for transmitting motor and sensory information between the cerebral cortex and other parts of the brain and spinal cord. It contains both ascending and descending fibers. The genu of the internal capsule specifically houses fibers that are involved in motor control.\r\n\r\nDamage or infarction in the genu of the internal capsule can disrupt the motor pathways that control various muscles, including those responsible for speech production. **Dysarthria** is a motor speech disorder characterized by difficulty in articulating words and may manifest as slurred or unclear speech.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 472-473.","responses":[{"text":"Visual impairment","correct":false,"visible":false},{"text":"Agitation","correct":false,"visible":false},{"text":"Dysarthria","correct":true,"visible":false},{"text":"Confusion","correct":false,"visible":false},{"text":"Auditory deficits","correct":false,"visible":false}]},{"id":12683,"text":"Which of the following cells line the central canal?","explanation":"**Ependymal cells** are specialized neuroglial cells that create and maintain cerebrospinal fluid (CSF). They form a barrier between the CSF-filled cavities and the surrounding neural tissue. In addition to their role in CSF production, ependymal cells also serve as a protective barrier, preventing harmful substances from entering the brain and spinal cord.\r\n\r\nFurthermore, ependymal cells possess cilia on their apical surfaces, which aid in the circulation of CSF. This movement of CSF is essential for distributing nutrients, removing waste products, and maintaining a stable environment within the central nervous system.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 59.","responses":[{"text":"Microglia","correct":false,"visible":false},{"text":"Multipolar neurons","correct":false,"visible":false},{"text":"Astrocytes","correct":false,"visible":false},{"text":"Oligodendrocytes","correct":false,"visible":false},{"text":"Ependymal cells","correct":true,"visible":false}]},{"id":12684,"text":"Which of the following is the correct option regarding the cerebellum?","explanation":"The correct statement regarding the cerebellum is that **Stellate and basket cells are present in the molecular layer**. The cerebellar cortex is organized into three layers: the molecular layer, the Purkinje cell layer, and the granular layer. The molecular layer, which is the outermost layer, contains two types of inhibitory interneurons: stellate cells and basket cells.\r\n\r\nStellate cells are found in the upper part of the molecular layer and are involved in modulating the activity of Purkinje cells by synapsing onto their dendrites. Basket cells are located closer to the Purkinje cell layer and are known for their axons that form a 'basket' around the Purkinje cell bodies, hence their name. Both stellate and basket cells play crucial roles in the inhibitory control of Purkinje cell activity, which is fundamental to the cerebellum's function in motor coordination.\r\n\r\nPurkinje neurons are not bipolar but rather have a highly branched dendritic tree. Purkinje cells are known for their extensive dendritic branching, not scarcity. The cerebellar cortex comprises molecular, Purkinje cell, and granular layers, not pyramidal layers. The superior cerebellar peduncle primarily connects the cerebellum to the midbrain, not the pons.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 231, 232, 235.","responses":[{"text":"Purkinje neurons are of bipolar variety","correct":false,"visible":false},{"text":"Superior cerebellar peduncle connects cerebellum to pons","correct":false,"visible":false},{"text":"Stellate and basket cells are present in the molecular layer","correct":true,"visible":false},{"text":"Molecular, granular, and pyramidal layers are present in cortex","correct":false,"visible":false},{"text":"Purkinje cells have scarce branching","correct":false,"visible":false}]},{"id":13029,"text":"The cuneocerebellar pathway conveys information from which of the following?","explanation":"In the case of the cuneocerebellar pathway, it conveys sensory information from the **muscles and joints of the upper limb and the upper part of the thorax.** This includes the proprioceptive feedback from the shoulder, arm, and upper chest regions. The pathway relays this information to the cerebellum, which plays a crucial role in coordinating and fine-tuning motor movements, maintaining balance, and ensuring precise control over muscle contractions.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 149.","responses":[{"text":"Muscles and joints of upper limb and upper part of thorax","correct":true,"visible":false},{"text":"Mid brain","correct":false,"visible":false},{"text":"Red nucleus","correct":false,"visible":false},{"text":"Muscles and joints of trunk and lower limb","correct":false,"visible":false},{"text":"Muscles and joints of upper and lower limb","correct":false,"visible":false}]},{"id":13030,"text":"During resting, the heart rate is slowed, pupils are constricted, peristalsis and glandular activity are increased, sphincters are opened, and the bladder wall is contracted. Which of the following system is activated in this state?","explanation":"In this scenario, the **parasympathetic nervous system** is dominant. It promotes a \"rest and digest\" response, which is characterized by slowing down heart rate, constricting pupils to aid near vision, increasing peristalsis (the movement of food through the digestive tract) and glandular activity for digestion, relaxing sphincters to facilitate the flow of substances, and causing the bladder wall to contract for controlled urination.\r\n\r\nIn contrast, the sympathetic nervous system typically elicits a \"fight or flight\" response, leading to increased heart rate, dilated pupils, decreased peristalsis, and other responses aimed at preparing the body for immediate action.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 390.","responses":[{"text":"Somatic nervous system","correct":false,"visible":false},{"text":"Sympathetic nervous system","correct":false,"visible":false},{"text":"Enteric nervous system","correct":false,"visible":false},{"text":"Parasympathetic nervous system","correct":true,"visible":false},{"text":"Autonomic nervous system","correct":false,"visible":false}]},{"id":13031,"text":"Meroanencephaly is defined as the partial absence of the brain. It is caused by which of the following defects?","explanation":"In normal embryogenesis, the neural tube, which eventually develops into the brain and spinal cord, forms from a process that involves the closure of two openings or neuropores: the anterior neuropore and the posterior neuropore. **Failure in the closure of the anterior neuropore** leads to meroanencephaly, which results in incomplete development of the brain in the affected region.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 500.","responses":[{"text":"Defect in regionalization","correct":false,"visible":false},{"text":"Disorder of myelination","correct":false,"visible":false},{"text":"Failure of closure of anterior neuropore","correct":true,"visible":false},{"text":"Failure of neural crest cells formation","correct":false,"visible":false},{"text":"Failure of closure of posterior neuropore","correct":false,"visible":false}]},{"id":13032,"text":"Cystic mass containing meninges with CSF only protrudes at the thoracolumbar region of a newborn. This cystic mass would be classified as which of the following defects?","explanation":"In **Spina Bifida Cystica with Meningocele**, there is a defect in the closure of the neural tube during fetal development, which leads to the protrusion of the meninges (protective membranes of the spinal cord) through the bony defect in the spine. Importantly, there is no involvement of the spinal cord or nerve roots in this type of spina bifida. The cystic mass typically contains CSF.\r\n\r\n**Spina Bifida Cystica with Meningomyelocele** involves the protrusion of both the meninges and the spinal cord or nerve roots. **Spina Bifida Occulta** is a milder form where the spinal cord and meninges do not protrude but there may be a bony defect in the spine. **Spina Bifida Aperta** is a general term for all types of spina bifida where there is an opening in the spine.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 498.","responses":[{"text":"Spina bifida","correct":false,"visible":false},{"text":"Spina bifida occulta","correct":false,"visible":false},{"text":"Spina bifida aperta","correct":false,"visible":false},{"text":"Spina bifida cystica with meningocele","correct":true,"visible":false},{"text":"Spina bifida cystica with meningomylocele","correct":false,"visible":false}]},{"id":13033,"text":"Basal nuclei are a collection of cell bodies that control voluntary movements. Which of the following vesicles gives rise to basal nuclei?","explanation":"These nuclei develop from the **Telencephalon**, which is one of the five primary vesicles formed during early embryonic brain development. The Telencephalon is responsible for giving rise to several important structures, including the cerebral cortex and the basal ganglia.\r\n\r\nSpecifically, the basal nuclei form from the basal part of the Telencephalon, and they are located deep within the cerebral hemispheres. They include structures like the caudate nucleus, putamen, and globus pallidus, among others. These nuclei are interconnected with various parts of the brain and are involved in regulating motor functions and coordinating movements.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 496.","responses":[{"text":"Metencephalon","correct":false,"visible":false},{"text":"Telencephalon","correct":true,"visible":false},{"text":"Diencephalon","correct":false,"visible":false},{"text":"Mesencephalon","correct":false,"visible":false},{"text":"Myelencephalon","correct":false,"visible":false}]},{"id":13034,"text":"A vascular lesion of the primary visual area (Brodmann area 17) may cause which one of the following defects?","explanation":"**Contralateral Homonymous Hemianopia with Macular Sparing** means that individuals with this condition experience a loss of vision in half of their visual field in both eyes, but with a notable exception. The central part of the visual field, known as the macula, is relatively spared from the effects of the lesion. This sparing occurs because the macula has a dedicated representation in the visual cortex and receives collateral blood supply, making it less susceptible to damage. In essence, while the peripheral vision is significantly impaired due to the lesion, central vision, including the macular region, remains relatively intact.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 473.","responses":[{"text":"Binasal hemianopia","correct":false,"visible":false},{"text":"Contralateral homonymous hemianopia with macular sparing","correct":true,"visible":false},{"text":"Blindness","correct":false,"visible":false},{"text":"Bitemporal hemianopia","correct":false,"visible":false},{"text":"Contralateral homonymous hemianopia","correct":false,"visible":false}]},{"id":13035,"text":"A 20-year-old girl presented with severe weight loss. On history, she admitted that her appetite is greatly reduced and she is experiencing sleep disturbances for the last two months. Which hypothalamic nucleus controls the appetite center?","explanation":"The **Lateral Hypothalamic Nucleus** is often referred to as the \"hunger center.\" It plays a pivotal role in stimulating hunger and food intake. When this nucleus is activated, it can trigger sensations of hunger, prompting an individual to seek and consume food.\r\n\r\nConversely, the **Paraventricular Nucleus**, located in the hypothalamus as well, is involved in appetite suppression. It is often termed the \"satiety center\" and is responsible for signaling fullness and reducing food intake.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 747.","responses":[{"text":"Lateral hypothalamic nuclei","correct":true,"visible":false},{"text":"Anterior hypothalamic nuclei","correct":false,"visible":false},{"text":"Medial hypothalamic nuclei","correct":false,"visible":false},{"text":"Paraventricular nuclei","correct":false,"visible":false},{"text":"Posterior hypothalamic nuclei","correct":false,"visible":false}]},{"id":13036,"text":"Which of the following tract conveys information about highly localized touch\r\nsensations and proprioception?","explanation":"The **Dorsal Column Tract**, also known as the **Medial Lemniscus Pathway**, is the primary tract responsible for conveying information related to highly localized touch sensations and proprioception. This tract plays a critical role in transmitting sensory input from the body's extremities, including the limbs and trunk, to the brain for processing and perception.\r\n\r\nThe pathway begins with specialized sensory receptors called **Meissner's corpuscles**, **Pacinian corpuscles**, and **muscle spindles**, which detect touch, pressure, and proprioceptive information, respectively. These receptors send their signals through sensory neurons that travel up the dorsal columns of the spinal cord.\r\n\r\nOnce these sensory neurons reach the medulla oblongata, they synapse in the **Gracile** and **Cuneate nuclei**. The axons of these second-order neurons then cross to the opposite side of the brainstem and ascend as the **Medial Lemniscus** to the thalamus.\r\n\r\nFrom the thalamus, the sensory information is further relayed to the **primary somatosensory cortex** in the postcentral gyrus of the parietal lobe, where the brain processes and interprets the sensations of touch and proprioception.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 142.","responses":[{"text":"Spino-reticular tract","correct":false,"visible":false},{"text":"Lateral spinothalamic tract","correct":false,"visible":false},{"text":"Spinocerebellar tract","correct":false,"visible":false},{"text":"Anterior spinothalamic tract","correct":false,"visible":false},{"text":"Dorsal column tract","correct":true,"visible":false}]},{"id":13062,"text":"A patient loses the sensation of crude touch, while the sensation of fine touch is intact. Which of the following tracts is most likely to be damaged?","explanation":"The loss of sensation of crude touch, while retaining the sensation of fine touch, suggests damage to the **Ventral spinothalamic tract**. The spinothalamic tracts (which include both the lateral and ventral spinothalamic tracts) are part of the anterolateral system and are responsible for transmitting various types of sensory information, including pain, temperature, and crude touch.\r\n\r\nThe ventral spinothalamic tract specifically carries information about crude touch and pressure. Crude touch refers to the general sensation of touch that is not finely localized or discriminative.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 142.","responses":[{"text":"Spinocerebellar tract","correct":false,"visible":false},{"text":"Dorsal column tract","correct":false,"visible":false},{"text":"Lateral spinothalamic tract","correct":false,"visible":false},{"text":"Ventral spinothalamic tract","correct":true,"visible":false},{"text":"Spino-reticular tract","correct":false,"visible":false}]},{"id":13063,"text":"A lesion in the dorsal column tract causes loss of proprioception resulting in severe ataxia. It can be confirmed by which of the following signs?","explanation":"The Romberg's test assesses a patient's ability to maintain balance with their eyes closed and feet together. A **positive Romberg's** test occurs when a patient exhibits significant swaying or loss of balance when their eyes are closed but can maintain balance with eyes open. This positive result indicates a deficiency in proprioception and the patient's reliance on visual input for balance, a condition known as **proprioceptive ataxia**.\r\n\r\n**Exaggerated tendon reflexes** are often associated with upper motor neuron lesions, such as those affecting the corticospinal tract, and are not a direct sign of dorsal column tract lesions. **Positive Babinski's sign** is indicative of upper motor neuron lesions as well, while **tremors** can have various causes and are not specific to dorsal column tract lesions. **Loss of tendon reflexes** is typically seen in lower motor neuron lesions.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 166, 241.","responses":[{"text":"Positive Romberg's test","correct":true,"visible":false},{"text":"Exaggerated tendon reflexes","correct":false,"visible":false},{"text":"Loss of tendon reflexes","correct":false,"visible":false},{"text":"Tremors","correct":false,"visible":false},{"text":"Positive Babinski's sign","correct":false,"visible":false}]},{"id":13064,"text":"A lesion in which of the following nuclei in the hypothalamus causes hypothalamic obesity?","explanation":"When the **ventromedial nucleus** nucleus is damaged or lesioned, it disrupts the balance of hunger and satiety signals in the hypothalamus. This disruption can result in uncontrolled overeating and a strong drive to consume food, leading to excessive weight gain and obesity. The ventromedial nucleus normally acts as a satiety center, helping to regulate food intake and maintain a healthy body weight.\r\n\r\nIn contrast, the lateral hypothalamic nucleus is often associated with hunger and feeding behavior. Lesions in the lateral hypothalamic nucleus can lead to reduced appetite and anorexia.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 747.","responses":[{"text":"Lateral hypothalamic nucleus","correct":false,"visible":false},{"text":"Dorso-medial nucleus","correct":false,"visible":false},{"text":"Supra-optic nucleus nucleus","correct":false,"visible":false},{"text":"Supra-chiasmatic nucleus","correct":false,"visible":false},{"text":"Ventromedial nucleus","correct":true,"visible":false}]},{"id":13065,"text":"Which of the following hypothalamic nuclei acts as the body's primary circadian pacemaker?","explanation":"The primary circadian pacemaker in the brain is the **suprachiasmatic nucleus (SCN)**, which is located in the **hypothalamus**. The SCN is responsible for regulating the body's internal clock and coordinating various physiological and behavioral processes with the natural light-dark cycle.\r\n\r\nThe SCN receives input from specialized ganglion cells in the retina that are sensitive to light and dark signals. These signals help synchronize the body's circadian rhythm with the external environment. When exposed to light, the SCN signals the pineal gland to inhibit the production of melatonin, a hormone that promotes sleep. As daylight fades, the SCN allows melatonin production to increase, signaling the body that it's time to sleep.\r\n\r\nThe SCN also influences various other processes, including body temperature, hormone secretion, and sleep-wake cycles.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 382.","responses":[{"text":"Ventromedial nucleus","correct":false,"visible":false},{"text":"Dorso-medial nucleus","correct":false,"visible":false},{"text":"Supra-chiasmatic nucleus","correct":true,"visible":false},{"text":"Red nucleus","correct":false,"visible":false},{"text":"Supra-optic nucleus","correct":false,"visible":false}]},{"id":13066,"text":"Which of the following is mostly associated with slow-wave sleep?","explanation":"Slow-wave sleep, which encompasses stages 3 and 4 of non-rapid eye movement (NREM) sleep, is mostly associated with **Sleep terrors**. Sleep terrors, also known as night terrors, are episodes of screaming, intense fear, and flailing while still asleep, and they predominantly occur during slow-wave sleep. \r\n\r\nThis stage of sleep is characterized by low frequency, high amplitude delta waves on EEG, and is considered the deepest phase of sleep. It's a period of reduced physiological activity, with decreased heart rate, respiratory rate, and metabolic rate. Slow-wave sleep is crucial for restorative processes and is thought to play a significant role in memory consolidation, although the relationship between memory and sleep stages is complex and involves multiple phases of sleep.\r\n\r\nHigh frequency EEG waves and most vivid dreaming are characteristic of REM (rapid eye movement) sleep, not slow-wave sleep. Irregular heart rate is not a typical feature of any specific sleep stage and could indicate a sleep-related disorder or other health issue.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 753.","responses":[{"text":"Irregular heart rate","correct":false,"visible":false},{"text":"Dreaming","correct":false,"visible":false},{"text":"High frequency EEG waves","correct":false,"visible":false},{"text":"Memory","correct":false,"visible":false},{"text":"Sleep terrors","correct":true,"visible":false}]},{"id":13067,"text":"Prolonged rapid eye movement (REM) sleep deprivation can result in which of the following?","explanation":"Prolonged rapid eye movement (REM) sleep deprivation can result in **Impaired memory**. REM sleep is a crucial phase of the sleep cycle that is intimately involved in the processing and consolidation of memories. During REM sleep, the brain is active, and many believe this stage to be essential for learning and memory formation.\r\n\r\nWhen deprived of REM sleep, individuals may experience difficulties with memory, particularly with the consolidation of new information and learning. This impairment can manifest as trouble remembering new facts, learning new skills, or forming new memories. The effect on memory can have broad implications, impacting academic performance, professional skills, and daily life tasks.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 756.","responses":[{"text":"Impaired driving","correct":false,"visible":false},{"text":"Teeth grinding","correct":false,"visible":false},{"text":"Increased appetite","correct":false,"visible":false},{"text":"Sleep terrors","correct":false,"visible":false},{"text":"Impaired memory","correct":true,"visible":false}]},{"id":13068,"text":"Maintaining working memory contents for a dozen seconds requires which of the following?","explanation":"The **prefrontal cortex** is a crucial brain region involved in executive functions, which encompass cognitive processes like working memory.\r\n\r\nWorking memory is the system that temporarily holds and manipulates information needed for cognitive tasks, decision-making, and problem-solving. It plays a fundamental role in various aspects of daily life, from following instructions to solving complex problems.\r\n\r\nThe prefrontal cortex, particularly the dorsolateral prefrontal cortex, is responsible for the temporary storage and manipulation of information during working memory tasks. Neurons in this region exhibit sustained firing patterns that maintain the representation of information for a brief period, allowing individuals to hold and manipulate information mentally. This function is essential for tasks like mental arithmetic, following multi-step instructions, and keeping track of items on a to-do list for short periods, such as a dozen seconds, before the information is either discarded or transferred to long-term memory.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 733.","responses":[{"text":"Amygdala","correct":false,"visible":false},{"text":"Prefrontal cortex","correct":true,"visible":false},{"text":"Cerebellum","correct":false,"visible":false},{"text":"Medial temporal lobe","correct":false,"visible":false},{"text":"Hippocampus","correct":false,"visible":false}]},{"id":13069,"text":"Young children can immediately repeat short sentences spoken by their parents and siblings, and also produce new sentences that follow the rules of their native language. The ability to produce new, rule-governed sentences is thought to involve which kind of learning?","explanation":"**Implicit learning** refers to the acquisition of knowledge and skills without conscious awareness of the learning process. It is often characterized by the gradual accumulation of knowledge through exposure and practice, leading to improved performance over time.\r\n\r\nIn the case of language acquisition in children, they are exposed to their native language from a very young age through interactions with family members and their environment. They unconsciously absorb the rules and structures of the language, allowing them to both mimic sentences they hear and generate new sentences that adhere to the grammatical rules they have internalized.\r\n\r\nThis process contrasts with explicit learning, which involves conscious effort and awareness, and it is more characteristic of formal education.","reference":"Dow Lecture Slides. Reproductive Module. Subject: Physiology, Topic: Learning and Memory, Sub-topic: Implicit Memory.","responses":[{"text":"Short-term","correct":false,"visible":false},{"text":"Explicit","correct":false,"visible":false},{"text":"Working","correct":false,"visible":false},{"text":"Long-term","correct":false,"visible":false},{"text":"Implicit","correct":true,"visible":false}]},{"id":13077,"text":"A 55-year-old male presents to the emergency department after a road traffic accident. Magnetic resonance imaging (MRI) shows damage to the corticospinal tract on one side. Which of the following tract serves as an \"alternative pathway\" for transmitting motor signals to the spinal cord?","explanation":"In the case of damage to the corticospinal tract, the **rubrospinal tract** serves as an \"alternative pathway\" for transmitting motor signals to the spinal cord. The rubrospinal tract originates in the red nucleus of the midbrain and descends to the spinal cord. Although it is less prominent in humans than in some other animals, it can partially compensate for the loss of function due to damage in the corticospinal tract.\r\n\r\nThe rubrospinal tract primarily facilitates the motor control of distal limb muscles, particularly flexor muscles, and plays a role in fine motor control. In the event of corticospinal tract damage, as seen in this patient, the rubrospinal tract can help maintain some motor functions, although it may not completely restore all lost functions.\r\n\r\nThe reticulospinal and vestibulospinal tracts are more involved in posture and balance control, the tectospinal tract in orienting movements of the head and neck, and the olivospinal tract is less significant in humans.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 700.","responses":[{"text":"Tectospinal tract","correct":false,"visible":false},{"text":"Vestibulospinal tract","correct":false,"visible":false},{"text":"Rubrospinal tract","correct":true,"visible":false},{"text":"Reticulospinal tract","correct":false,"visible":false},{"text":"Olivospinal tract","correct":false,"visible":false}]},{"id":13078,"text":"The sweat glands and piloerector muscles of hairy skin are innervated by which of the following fiber types?","explanation":"The sweat glands and piloerector muscles of hairy skin are primarily innervated by **cholinergic postganglionic sympathetic fibers**. \r\n\r\nIn the sympathetic nervous system, the preganglionic neurons release acetylcholine (a cholinergic neurotransmitter) at the ganglion, where it binds to nicotinic receptors. This then activates the postganglionic neurons. In the case of sweat glands and piloerector muscles, the postganglionic sympathetic neurons also release acetylcholine at their synapses with these target tissues. \r\n\r\nActivation of cholinergic postganglionic sympathetic fibers leads to specific responses:\r\n1. **Sweat Glands:** These fibers stimulate the sweat glands to produce and secrete sweat, which helps regulate body temperature by dissipating heat through evaporative cooling.\r\n\r\n2. **Piloerector Muscles:** These fibers are responsible for the contraction of piloerector muscles, causing hair to stand on end. This response is often referred to as \"goosebumps\" and is a vestigial reflex in humans that occurs in response to cold or emotional stimuli.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 765.","responses":[{"text":"Adrenergic postganglionic sympathetic","correct":false,"visible":false},{"text":"Cholinergic postganglionic parasympathetic","correct":false,"visible":false},{"text":"Adrenergic preganglionic sympathetic","correct":false,"visible":false},{"text":"Adrenergic preganglionic parasympathetic","correct":false,"visible":false},{"text":"Cholinergic postganglionic sympathetic","correct":true,"visible":false}]},{"id":13079,"text":"Which type of cholinergic receptor is found at synapses between preganglionic and postganglionic neurons of the sympathetic system?","explanation":"**Nicotinic receptors** are named after nicotine, a substance found in tobacco, which can stimulate these receptors. These receptors are ion channels that respond to the binding of acetylcholine, a neurotransmitter released by preganglionic sympathetic neurons at their synapses with postganglionic neurons.\r\n\r\nWhen acetylcholine binds to nicotinic receptors, it triggers the opening of ion channels, allowing the flow of sodium ions into the postganglionic neuron and potassium ions out of the neuron. This influx of sodium ions depolarizes the postganglionic neuron, leading to the generation of an action potential that propagates the nerve signal.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 765.","responses":[{"text":"Muscarinic","correct":false,"visible":false},{"text":"Alpha","correct":false,"visible":false},{"text":"Beta 2","correct":false,"visible":false},{"text":"Nicotinic","correct":true,"visible":false},{"text":"Beta 1","correct":false,"visible":false}]},{"id":13080,"text":"Which of the following nerve fiber types is most sensitive to anesthetic agents?","explanation":"**C fibers** are a type of unmyelinated nerve fibers that primarily transmit pain signals and temperature sensations. They have a small diameter and lack myelin, which makes them slower in conducting nerve impulses compared to other fiber types. This lack of myelin also renders them more susceptible to the effects of anesthetic agents.\r\n\r\nAnesthetic agents, such as local anesthetics and general anesthetics, work by interfering with nerve signal transmission. They block the propagation of action potentials along nerve fibers by inhibiting the function of voltage-gated sodium channels, which are essential for the initiation and propagation of nerve impulses. Since C fibers are already slower in conducting nerve impulses and lack the insulation provided by myelin, they are particularly vulnerable to the inhibitory effects of anesthetic agents.","reference":"Accessed December 10, 2022. https://pubs.asahq.org/anesthesiology/article/95/6/5A/39210/Susceptibility-of-Nerve-Fibers-to-Local-Anesthesia","responses":[{"text":"C fibers","correct":true,"visible":false},{"text":"A delta fibers","correct":false,"visible":false},{"text":"A gamma fibers","correct":false,"visible":false},{"text":"A alpha fibers","correct":false,"visible":false},{"text":"B fibers","correct":false,"visible":false}]},{"id":13081,"text":"Which one of the following is the capability of the brain to ignore unimportant information?","explanation":"**Habituation** is a fundamental neural process that allows the brain to filter out repetitive or non-essential stimuli from the environment. It is a form of non-associative learning where an organism's response to a specific stimulus decreases over time if that stimulus is repeated without any significant consequence. In other words, the brain becomes less responsive to stimuli that are perceived as irrelevant or unimportant, allowing it to allocate its cognitive resources to more critical tasks.\r\n\r\nFor example, when you first enter a room with a ticking clock, you may notice the sound, but as time goes on and the ticking remains constant, your brain habituates to the sound, and you eventually stop paying attention to it.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 736.","responses":[{"text":"Facilitation","correct":false,"visible":false},{"text":"Reverberation","correct":false,"visible":false},{"text":"Consolidation","correct":false,"visible":false},{"text":"Sensitization","correct":false,"visible":false},{"text":"Habituation","correct":true,"visible":false}]},{"id":13082,"text":"A patient presents with the inability to interpret thoughts, although he is capable of expressing individual words or even short phrases. Which area of the brain is most likely to be affected?","explanation":"The patient's inability to interpret thoughts while still being able to express individual words or short phrases suggests a condition known as **Wernicke's aphasia**. This condition typically results from damage to **Wernicke's area**, which is located in the **left hemisphere of the brain** in the posterior part of the **superior temporal gyrus**.\r\n\r\nWernicke's area plays a crucial role in language comprehension and the formulation of coherent, meaningful sentences. When this area is affected, as in cases of injury or disease, it disrupts the patient's ability to understand language, leading to fluent but nonsensical speech. Individuals with Wernicke's aphasia often produce sentences with grammatically correct structure but use words inappropriately or create sentences that do not make logical sense.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 729.","responses":[{"text":"Wernicke's area","correct":true,"visible":false},{"text":"Angular gyrus","correct":false,"visible":false},{"text":"Broca's area","correct":false,"visible":false},{"text":"Arcuate fasciculus","correct":false,"visible":false},{"text":"Exner's area","correct":false,"visible":false}]},{"id":13083,"text":"During the removal of a brain tumor in a patient, a part of the brain was removed. Upon successful awakening, the patient is unable to form new memories. However, he can recall most previously learned memories satisfactorily. Which of the brain area may have been affected during the operation?","explanation":"The patient's inability to form new memories while retaining the ability to recall previously learned memories is indicative of a condition known as **anterograde amnesia**. This condition is often associated with damage to the **hippocampus**, a critical region of the brain for the formation of new memories.\r\n\r\nThe hippocampus is part of the **limbic system**, and it plays a central role in the **conversion of short-term memories into long-term memories** through a process called memory consolidation. When this area is damaged, as might occur during brain surgery, the individual may find it extremely challenging or impossible to create new memories, even though their ability to remember events and information from before the damage remains intact.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 739.","responses":[{"text":"Anterior hypothalamic nucleus","correct":false,"visible":false},{"text":"Suprachiasmatic nucleus","correct":false,"visible":false},{"text":"Epithalamus","correct":false,"visible":false},{"text":"Arcuate nucleus","correct":false,"visible":false},{"text":"Hippocampus","correct":true,"visible":false}]},{"id":13087,"text":"Which of the following functions is the result of an increased activity of the sympathetic nervous system?","explanation":"Increased activity of the sympathetic nervous system, often referred to as the \"fight or flight\" response, leads to several physiological changes that prepare the body for physical exertion and increased alertness. One of the functions resulting from this heightened sympathetic activity is **bronchiolar dilation**.\r\n\r\nWhen the sympathetic nervous system is activated, it releases norepinephrine, which binds to beta-adrenergic receptors in the bronchiolar smooth muscle. This binding triggers a cascade of events that ultimately leads to relaxation of the bronchial smooth muscle, causing the bronchioles to dilate. Bronchiolar dilation increases airflow to the lungs, enhancing oxygen exchange, and facilitating improved oxygen delivery to tissues during times of stress or physical activity.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 769.","responses":[{"text":"Pupillary constriction","correct":false,"visible":false},{"text":"Gallbladder emptying","correct":false,"visible":false},{"text":"Accommodation for near vision","correct":false,"visible":false},{"text":"Bronchiolar dilation","correct":true,"visible":false},{"text":"Penile erection","correct":false,"visible":false}]},{"id":13107,"text":"Long-term potentiation is identified in hippocampal mossy fibers by an increase in which of the following ions in the postsynaptic area?","explanation":"**Long-term potentiation (LTP)** is a cellular mechanism that underlies learning and memory processes in the brain, particularly in the hippocampus. It involves a persistent increase in the strength of synaptic connections between neurons. In hippocampal mossy fibers, this increase is identified by an increase in **calcium ions (Ca2+)** in the postsynaptic area.\r\n\r\nThe process of LTP typically involves the following steps:\r\n1. **Glutamate Release**: When a presynaptic neuron (mossy fiber) is stimulated, it releases the neurotransmitter glutamate into the synapse.\r\n2. **Receptor Activation**: Glutamate binds to receptors on the postsynaptic neuron, specifically the NMDA (N-methyl-D-aspartate) receptors.\r\n3. **Calcium Influx**: Activation of NMDA receptors allows calcium ions (Ca2+) to enter the postsynaptic neuron. This influx of calcium is crucial for the induction of LTP.\r\n4. **Signal Amplification**: Increased calcium levels in the postsynaptic neuron activate various intracellular signaling pathways, leading to changes in synaptic strength. This involves the insertion of more AMPA receptors into the postsynaptic membrane, making the synapse more responsive to glutamate.","reference":"Yeckel MF, Kapur A, Johnston D. Multiple forms of LTP in hippocampal CA3 neurons use a common postsynaptic mechanism. Nature neuroscience. Published July 1999. Accessed December 10, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2951317/","responses":[{"text":"Potassium","correct":false,"visible":false},{"text":"Magnesium","correct":false,"visible":false},{"text":"Calcium","correct":true,"visible":false},{"text":"Sodium","correct":false,"visible":false},{"text":"Phosphorus","correct":false,"visible":false}]},{"id":13187,"text":"During an examination of a young boy, the child feels very ticklish so it becomes difficult for the doctor to examine him. Which of the following tract carries the above sensation?","explanation":"The sensation of ticklishness experienced by the young boy during the examination is carried by the **anterior spinothalamic tract**. This tract is part of the broader spinothalamic pathway responsible for transmitting various sensory signals, including those related to light touch, pressure, and tickling.\r\n\r\nWhen the doctor touches or tickles the child during the examination, sensory receptors in the skin are stimulated. These receptors, such as **Meissner's corpuscles** and **free nerve endings**, detect changes in pressure and movement on the skin's surface. The sensory information generated by this stimulation is then transmitted through the anterior spinothalamic tract to reach the brain.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 142.","responses":[{"text":"Corticospinal tract","correct":false,"visible":false},{"text":"Lateral spinothalamic tract","correct":false,"visible":false},{"text":"Anterior spinothalamic tract","correct":true,"visible":false},{"text":"Dorsal column medial leminiscal system","correct":false,"visible":false},{"text":"Spinocerebellar tract","correct":false,"visible":false}]},{"id":13188,"text":"During suturing of a wound, a patient receives local anesthesia around the wound area. After this, he did not feel any needle pain during suturing. Which of the following option could be the reason for this?","explanation":"Local anesthesia agents, such as lidocaine or bupivacaine, work by **blocking sodium channels** in the nerve cell membranes. These sodium channels are responsible for the initiation and propagation of action potentials (nerve signals). When these channels are blocked, the influx of sodium ions into the nerve cells is inhibited, preventing the generation and transmission of pain signals along the nerves.","reference":"Le T, Bhushan V, Qiu C, et al., eds. First Aid for the USMLE Step 1 2023. 33rd ed. McGraw Hill; 2023: 567.","responses":[{"text":"Blockage of voltage-gated Na⁺ channels","correct":true,"visible":false},{"text":"Opening of ligand-gated Na⁺ channels","correct":false,"visible":false},{"text":"Blockage of ligand-gated K⁺ channels","correct":false,"visible":false},{"text":"Early closure of voltage-gated Na⁺ channels","correct":false,"visible":false},{"text":"Blockage of voltage-gated K⁺ channels","correct":false,"visible":false}]},{"id":13189,"text":"Which of the following sensations are relayed at the ventral posterolateral nuclei of the thalamus before reaching the post-central gyrus?","explanation":"The ventral posterolateral nucleus (VPL) of the thalamus serves as a vital relay station in the sensory pathway, particularly for **somatic afferents** originating from **the trunk and limbs**. As a result, sensations from the trunk and limbs, including the sensation of touch, pressure, temperature, and awareness of limb position, are all **relayed at the VPL nucleus** before reaching the post-central gyrus. This allows for the conscious perception and interpretation of sensory input from these body regions.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 366.","responses":[{"text":"Somatic afferents from head and arms","correct":false,"visible":false},{"text":"Somatic afferents from trunk and limbs","correct":true,"visible":false},{"text":"Visceral afferents from gut","correct":false,"visible":false},{"text":"Visceral afferents from gut","correct":false,"visible":false},{"text":"Somatic afferents from head and limbs","correct":false,"visible":false}]},{"id":13190,"text":"Secretion of melatonin by the pineal gland is regulated by which one of the following parts of the diencephalon?","explanation":"Melatonin is a hormone responsible for regulating our sleep-wake cycle and circadian rhythms. The secretion of melatonin is influenced by the environmental light-dark cycle. During periods of darkness, the pineal gland synthesizes and releases melatonin, which helps to induce sleepiness and coordinate various physiological processes with the day-night cycle.\r\n\r\nThe regulation of melatonin secretion occurs through the influence of the **hypothalamus**. The suprachiasmatic nucleus (SCN) of the hypothalamus acts as the body's internal biological clock and receives information about the daily light-dark cycle. In response to darkness, the SCN signals the pineal gland to release melatonin, facilitating the transition to the sleep phase.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 253.","responses":[{"text":"Globus pallidus","correct":false,"visible":false},{"text":"Epithalamus","correct":false,"visible":false},{"text":"Hypothalamus","correct":true,"visible":false},{"text":"Subthalamus","correct":false,"visible":false},{"text":"Metathalamus","correct":false,"visible":false}]},{"id":13191,"text":"Which of the following is the rate-limiting enzyme of acetylcholine synthesis?","explanation":"The rate-limiting enzyme in the synthesis of acetylcholine is **Choline Acetyltransferase (ChAT)**. Acetylcholine is a crucial neurotransmitter found in both the central nervous system (CNS) and the peripheral nervous system (PNS). It plays a pivotal role in various physiological processes, including muscle contraction, autonomic nervous system functions, and cognitive functions.\r\n\r\nChAT is responsible for catalyzing the synthesis of acetylcholine by combining **acetyl coenzyme A (acetyl CoA)** and **choline**. This reaction takes place in the nerve terminal, where acetyl CoA and choline are brought together to form acetylcholine. The acetylcholine synthesized is then stored in synaptic vesicles, ready for release when a nerve impulse arrives at the nerve terminal.","reference":"(1) Chatterjea MN, Shinde R. Textbook of Medical Biochemistry. 8th ed. Jaypee Brothers Medical Publications; 2012: 442 (2 )Choline acetyltransferase - an overview | sciencedirect topics. Accessed December 10, 2022. https://www.sciencedirect.com/topics/neuroscience/choline-acetyltransferase","responses":[{"text":"Phenylalanine hydroxylase","correct":false,"visible":false},{"text":"Choline acetyl transferase","correct":true,"visible":false},{"text":"Tyrosine hydroxylase","correct":false,"visible":false},{"text":"Aminotransferase","correct":false,"visible":false},{"text":"Choline esterase","correct":false,"visible":false}]},{"id":13193,"text":"What is the reason that brain tissue cannot utilize fatty acids for energy?","explanation":"The primary reason brain tissue cannot utilize fatty acids for energy is that **fatty acids are attached with albumin in blood**. This binding to albumin restricts their transport across the blood-brain barrier, making them largely unavailable to brain tissue.\r\n\r\nFatty acids in the blood are typically bound to albumin, a protein that aids in their transport. However, due to their large size and the characteristics of the blood-brain barrier, which selectively restricts the passage of certain substances into the brain, these albumin-bound fatty acids cannot efficiently traverse into the brain tissue. As a result, the brain predominantly relies on glucose for its energy needs.","reference":"Biochemistry 11: Regulation and Integration. https://www.cureffi.org/2013/12/06/biochemistry-11-regulation-and-integration/. Accessed 24 Dec. 2022.","responses":[{"text":"Enzymes of beta-oxidation are present in the brain","correct":false,"visible":false},{"text":"They are not found in brain tissue","correct":false,"visible":false},{"text":"They cannot pass through blood-brain barrier","correct":false,"visible":false},{"text":"Fatty acids are attached with albumin in blood","correct":true,"visible":false},{"text":"They are utilized in ganglioside formation","correct":false,"visible":false}]},{"id":13194,"text":"A compound that is synthesized in a neuron, has a receptor in vicinity, and has agonists and antagonists defines which of the following terms?","explanation":"**Neurotransmitters** are essential signaling molecules in the nervous system that play a crucial role in transmitting signals from one neuron to another, or from neurons to target cells such as muscle cells or glands.\r\n\r\nNeurotransmitters like serotonin, dopamine, acetylcholine, and glutamate are essential for transmitting signals in the nervous system, and their precise regulation is crucial for proper neurological function. They play roles in various physiological processes, including mood regulation, muscle contraction, and sensory perception.","reference":"Neurotransmitters: what they are, functions \u0026 types. Cleveland Clinic. Accessed December 10, 2022. https://my.clevelandclinic.org/health/articles/22513-neurotransmitters","responses":[{"text":"Neurohormone","correct":false,"visible":false},{"text":"Neuromediator","correct":false,"visible":false},{"text":"Neuropeptide","correct":false,"visible":false},{"text":"Neurochemical mediator","correct":false,"visible":false},{"text":"Neurotransmitter","correct":true,"visible":false}]},{"id":13197,"text":"Practicing a healthy lifestyle by eating a diet rich in fruits and vegetables, and maintaining a healthy weight for the prevention of hypertension and stroke is advised by physicians. Which one of the following preventions is applied here?","explanation":"**Primary Prevention** involves taking proactive measures to prevent the initial occurrence of a disease or condition. In this case, individuals are encouraged to adopt healthy habits and make lifestyle choices that reduce the risk of developing hypertension (high blood pressure) and, subsequently, the risk of stroke. This approach targets the general population or individuals who are currently healthy but at risk for certain diseases due to their lifestyle or genetic factors.\r\n\r\nThe goal of primary prevention is to promote health, reduce risk factors, and prevent the onset of diseases before they occur. It includes measures such as health education, lifestyle modifications, vaccination, and environmental changes to promote overall well-being and reduce the incidence of diseases.","reference":"Dow Lecture Slides. Reproductive Module. Subject: Community Medicine, Topic: Prevalence and Risk Factors of Stroke in Community and its Prevention, Sub-topic: Prevention of Stroke.","responses":[{"text":"Secondary","correct":false,"visible":false},{"text":"Quarternary","correct":false,"visible":false},{"text":"Primary","correct":true,"visible":false},{"text":"Primordial","correct":false,"visible":false},{"text":"Tertiary","correct":false,"visible":false}]},{"id":13198,"text":"A surgeon working in a private rehabilitation facility encounters a patient with a certain tumor that responds only to radiotherapy and surgery. The surgeon is enthusiastic to perform the surgery and proceeds to convince the patient to perform the surgery despite the lack of evidence of surgery being the better option. Which of the following principles of ethical communication has the surgeon breached in the above scenario?","explanation":null,"reference":"Dow Lecture Slides. Neuroscience module, Subject: Medical Ethics; Topic: Ethical Communication Skills; Sub-topic: Principles of Ethical Communication.","responses":[{"text":"Beneficence","correct":false,"visible":false},{"text":"Honesty and truthfulness","correct":true,"visible":false},{"text":"Equity and justice","correct":false,"visible":false},{"text":"Active listening","correct":false,"visible":false},{"text":"Empathy","correct":false,"visible":false}]},{"id":13199,"text":"Which of the following statements is correct regarding the mu receptor stimulation?","explanation":"Stimulation of the mu receptor, a type of opioid receptor, is associated with **respiratory depression**. This occurs because mu receptors are present in the brainstem areas that control respiration, specifically the medulla oblongata.\r\n\r\nWhen these receptors are stimulated, there is a decrease in the responsiveness of the brain's respiratory centers to carbon dioxide. As a result, there is a reduction in the rate and depth of breathing. This effect can be particularly pronounced with higher doses of opioids, leading to severe respiratory depression, which can be life-threatening.","reference":"Dow Lecture Slides. Neuroscience Module. Subject: Pharmacology, Topic: Opioids, Sub-topic: Receptor Stimulation.","responses":[{"text":"Analgesia (spinal)","correct":false,"visible":false},{"text":"Sedation","correct":false,"visible":false},{"text":"Miosis","correct":false,"visible":false},{"text":"Hallucinations","correct":false,"visible":false},{"text":"Respiratory depression","correct":true,"visible":false}]},{"id":13200,"text":"A 39-year-old woman has had a severe headache for 3 days. On physical examination,\r\nshe is afebrile and normotensive. Fundoscopic examination shows papilledema on the\r\nright. One day later, she has right pupillary dilation and impaired ocular movement. Which of the following lesions best explains these findings?","explanation":"**Transtentorial medial temporal herniation** occurs when the medial part of the temporal lobe herniates or shifts downward through the tentorial notch due to increased intracranial pressure. Importantly, within the tentorial notch, the oculomotor nerve (CN III) and the posterior cerebral artery are located in close proximity. As a result of the herniation, these structures can be compressed. This compression of CN III leads to pupillary dilation (mydriasis) on the affected side and impaired ocular movement. These signs are often referred to as a \"blown pupil.\"","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2018: 183.","responses":[{"text":"Transtentorial medial temporal herniation","correct":true,"visible":false},{"text":"Ruptured middle cerebral berry aneurysm","correct":false,"visible":false},{"text":"Chronic subdural hematoma","correct":false,"visible":false},{"text":"Frontal lobe abscess","correct":false,"visible":false},{"text":"Hydrocephalus ex vacuo","correct":false,"visible":false}]},{"id":13201,"text":"An 85-year-old male is in a coma in a hospital. His daughter makes all the decisions regarding his treatment on his behalf. Which of the following options best describes the type of consent in this scenario?","explanation":"**Surrogate consent,** also known as substituted consent or proxy consent, occurs when an individual is unable to make medical decisions for themselves, often due to incapacity or unconsciousness. In such cases, a designated surrogate decision-maker, often a family member or legal guardian, assumes the responsibility of making healthcare decisions on behalf of the incapacitated person. The surrogate decision-maker typically follows the patient's previously expressed wishes, if known, or makes decisions based on what they believe to be in the patient's best interests.","reference":"(1) Mendyk AM, Labreuche J, Henon H, et al. Which factors influence the resort to surrogate consent in stroke trials, and what are the patient outcomes in this context? BMC Medical Ethics. Published April 24, 2015. Accessed December 25, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4415257/\r\n\r\n(2) Consent and surrogate decision making - special subjects. MSD Manual Professional Edition. Accessed December 25, 2022. https://www.msdmanuals.com/professional/special-subjects/medicolegal-issues/consent-and-surrogate-decision-making","responses":[{"text":"Surrogate consent","correct":true,"visible":false},{"text":"Expressed consent","correct":false,"visible":false},{"text":"Informed consent","correct":false,"visible":false},{"text":"Opt-out consent","correct":false,"visible":false},{"text":"Implied consent","correct":false,"visible":false}]},{"id":13202,"text":"A 15-year-old girl presented to the outpatient department with complaints of headaches for the past 8 months. Over a 2-week period, she has a generalized seizure. On physical examination, there is no papilledema or movement disorder. Computed tomography (CT) scan of the head shows a 2 cm mass in the right frontal lobe and shows evidence of recent and remote hemorrhage. What is the most likely diagnosis?","explanation":"An **arteriovenous Malformation (AVM)** is a vascular abnormality characterized by a tangle of arteries and veins in the brain, which bypasses the normal capillary system. These abnormal connections between arteries and veins create a risk for bleeding or hemorrhage, leading to neurological symptoms. \r\n\r\nIn this scenario, the patient's history of headaches over several months, followed by a generalized seizure, is indicative of a neurological problem. The CT scan revealing a 2 cm mass in the right frontal lobe with evidence of recent and remote hemorrhage is consistent with an AVM. The bleeding or hemorrhage can cause neurological symptoms, such as seizures, and may explain the headaches.","reference":"Klatt EC, Kumar V. Robbins and Cotran Review of Pathology. Fifth edition. Elsevier Saunders; 2022: 437, 449.","responses":[{"text":"Organizing abscess","correct":false,"visible":false},{"text":"Arteriovenous malformation","correct":true,"visible":false},{"text":"Prior head trauma","correct":false,"visible":false},{"text":"Ruptured saccular aneurysm","correct":false,"visible":false},{"text":"Angiosarcoma","correct":false,"visible":false}]},{"id":13203,"text":"Which of the following is a modifiable risk factor for stroke?","explanation":"Stroke is a serious medical condition characterized by the sudden interruption of blood flow to the brain, leading to brain damage. While some risk factors for stroke, like family history, age, and genetics, are non-modifiable and cannot be changed, others, such as **obesity,** can be modified through lifestyle changes.\r\n\r\nObesity is associated with several risk factors that increase the likelihood of stroke, including hypertension (high blood pressure), diabetes, high cholesterol levels, and heart disease. Excess body weight can contribute to the development of these conditions, which, in turn, elevate the risk of stroke. Obesity can also lead to inflammation and the formation of blood clots, further increasing stroke risk.","reference":"Dow Lecture Slides. Reproductive Module. Subject: Community Medicine, Topic: Prevalence and Risk Factors of Stroke in Community and its Prevention, Sub-topic: Risk Factors.","responses":[{"text":"Genetics","correct":false,"visible":false},{"text":"Obesity","correct":true,"visible":false},{"text":"Gender","correct":false,"visible":false},{"text":"Family history","correct":false,"visible":false},{"text":"Age","correct":false,"visible":false}]},{"id":13207,"text":"Peripheral nerves are often damaged in many different forms of different vasculitis including polyarteritis nodosa (PAN), Churg-Strauss syndrome, and Wegener’s granulomatosis. Which of the following is the most common clinical picture in these disorders?","explanation":"The most common clinical picture in vasculitis disorders such as polyarteritis nodosa (PAN), Churg-Strauss syndrome, and Wegener’s granulomatosis involving peripheral nerves is **mononeuritis multiplex.**\r\n\r\nMononeuritis multiplex is a neurological condition characterized by the simultaneous or sequential involvement of multiple individual peripheral nerves. It results from the inflammation and damage of these nerves due to the vasculitis process. In these disorders, the immune system mistakenly attacks the blood vessels, including those supplying peripheral nerves, leading to impaired blood flow and nerve damage.\r\n\r\nPatients with mononeuritis multiplex may experience a variety of neurological symptoms, depending on which nerves are affected. These symptoms can include weakness, numbness, tingling, and loss of muscle function in specific areas corresponding to the damaged nerves. The condition often presents as a patchwork of neurological deficits, making it distinct from other neuropathies like polyneuropathy, which typically involves a more generalized and symmetric distribution of nerve damage.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1220.","responses":[{"text":"Loss of sensation in limbs","correct":false,"visible":false},{"text":"Autonomic neuropathy","correct":false,"visible":false},{"text":"Combination neuropathy","correct":false,"visible":false},{"text":"Mononeuritis multiplex","correct":true,"visible":false},{"text":"Polyneuropathy","correct":false,"visible":false}]},{"id":13210,"text":"As a medical professional, you have to come up with ideas for research that are original, unique, new, and relevant to your field of practice. This involves creative thinking. Which of the following will you follow?","explanation":"The most effective sequence for fostering creative thinking in research is the **\"Preparation, Incubation, Illumination, Evaluation, Implementation\"** model. In the **preparation** phase, researchers build a solid foundation of knowledge by reviewing existing literature and identifying research gaps. Following this, during the **incubation** stage, they take a step back from active problem-solving and allow their subconscious mind to process information, often leading to new insights. The \"Aha!\" moment, known as **illumination**, occurs when a creative solution or research idea becomes clear. In the **evaluation** phase, researchers critically assess the feasibility and relevance of the idea, ensuring it addresses a specific research question or problem. Finally, in the **implementation** phase, the research idea is put into action through experimental design, data collection, and research execution.","reference":"Dow Lecture Slides. Neuroscience Module. Subject: Behavioural Sciences, Topic: Thinking, Sub-topic: 5 stages of Creative Process.","responses":[{"text":"Preparation, accommodation, assimilation, centration, egocentrism","correct":false,"visible":false},{"text":"Incubation, preparation, revision, accommodation, centration","correct":false,"visible":false},{"text":"Assimilation, centration, egocentrism, incubation, revision","correct":false,"visible":false},{"text":"Preparation, incubation, illumination, evaluation, implementation","correct":true,"visible":false},{"text":"Accommodation, centration, egocentrism, incubation, revision","correct":false,"visible":false}]},{"id":13211,"text":"Ali saw a snake and he started trembling. The statement that Ali is afraid because he trembled is better explained by which of the following theories?","explanation":"The statement that Ali is afraid because he trembled is better explained by the **James-Lange theory** of emotions. According to this theory, emotional experiences are a result of physiological responses to external stimuli. In Ali's case, seeing the snake (the external stimulus) triggers a physiological response, which, in this case, is trembling. According to the James-Lange theory, Ali interprets his trembling as a bodily response to the perceived threat (the snake) and, in turn, experiences fear. In essence, this theory suggests that our emotional experiences are the product of our body's physiological reactions to stimuli, rather than the other way around. It highlights the role of bodily sensations in shaping our emotional responses and is one of the foundational theories in the study of emotions.","reference":"Dow Lecture Slides. Neuroscience Module. Subject: Behavioural Sciences, Topic: Emotions, Sub-topic: Theories of Emotion.","responses":[{"text":"Cannon-Bard theory","correct":false,"visible":false},{"text":"James-Lange theory","correct":true,"visible":false},{"text":"Darwin's theory","correct":false,"visible":false},{"text":"Two-factor theory","correct":false,"visible":false},{"text":"Appraisal theory","correct":false,"visible":false}]},{"id":13212,"text":"Destructive lesion of the Wernicke's area results in which of the following?","explanation":"A destructive lesion of **Wernicke's area** in the cerebral cortex typically results in **receptive aphasia**. Receptive aphasia, also known as Wernicke's aphasia, is a language disorder characterized by impaired comprehension of spoken and written language. Individuals with receptive aphasia may produce fluent and grammatically correct speech, but the content of their speech lacks meaningful words and may include neologisms (made-up words) and paraphasias (substituting one word for another). \r\n\r\nIn this condition, although individuals can speak fluently and effortlessly, their speech is often incomprehensible to others, and they may not recognize their own language errors. They may also have difficulty understanding spoken or written language, making it challenging for them to engage in meaningful communication.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 290.","responses":[{"text":"Global aphasia","correct":false,"visible":false},{"text":"Astereognosis","correct":false,"visible":false},{"text":"Agraphia","correct":false,"visible":false},{"text":"Receptive aphasia","correct":true,"visible":false},{"text":"Expressive aphasia","correct":false,"visible":false}]},{"id":13213,"text":"Which nerve exits the skull from the internal acoustic meatus along with the vestibulocochlear nerve (CN VIII)?","explanation":"The **facial nerve (CN VII)**, which controls facial muscles and carries taste sensations from the anterior two-thirds of the tongue, also exits the skull through the internal acoustic meatus in close proximity to the vestibulocochlear nerve.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 338.","responses":[{"text":"Vagus nerve (CN X)","correct":false,"visible":false},{"text":"Facial nerve (CN VII)","correct":true,"visible":false},{"text":"Trigeminal nerve (CN V)","correct":false,"visible":false},{"text":"Glossopharyngeal nerve (CN IX)","correct":false,"visible":false},{"text":"Abducens nerve (CN VI)","correct":false,"visible":false}]},{"id":13234,"text":"What is the absolute contraindication of magnetic resonance imaging (MRI)?","explanation":"**Indwelling cardiac pacemakers** contain electronic components that can be affected by the strong magnetic fields of an MRI machine. The magnetic field can potentially disrupt the function of the pacemaker, leading to serious cardiac complications.\r\n\r\nTherefore, individuals with cardiac pacemakers are considered an absolute contraindication for MRI. Alternative imaging methods, such as computed tomography (CT) scans or ultrasound, may be recommended for these individuals when imaging is necessary.","reference":"Ghadimi M, Sapra A. Magnetic resonance imaging contraindications. In: StatPearls. StatPearls Publishing; 2022. Accessed December 10, 2022. http://www.ncbi.nlm.nih.gov/books/NBK551669/","responses":[{"text":"Allergies","correct":false,"visible":false},{"text":"Dyspnea","correct":false,"visible":false},{"text":"Claustrophobia","correct":false,"visible":false},{"text":"Indwelling cardiac pace maker","correct":true,"visible":false},{"text":"Movement Disorders","correct":false,"visible":false}]},{"id":13235,"text":"A 25-year-old male is brought to the emergency department with complaints of all four\r\nlimbs weakness for 3 days with a history of diarrhea 3 weeks before. On examination, he has flaccid areflexic quadriparesis and the sensations are intact with downgoing plantar. What should be the diagnostic investigation in this case?","explanation":"The patient's presentation of weakness in all four limbs, along with a history of diarrhea, raises suspicion of Guillain-Barré syndrome (GBS). GBS is an autoimmune condition that affects the peripheral nervous system. **Nerve conduction studies** play a critical role in diagnosing GBS.\r\n\r\nIn GBS, nerve conduction studies often reveal characteristic findings, including slowed or absent nerve conduction velocities and abnormal sensory and motor responses. These findings help confirm the diagnosis and determine the extent of nerve damage.","reference":"Dow Lecture Slides. Neuroscience Module. Subject: Neurology, Topic: Investigations of Neurological Disorders, Sub-topic: Diagnostic Plan.","responses":[{"text":"Nerve conduction studies","correct":true,"visible":false},{"text":"Serum electrolytes","correct":false,"visible":false},{"text":"Cerebrospinal fluid detailed report (CSF DR)","correct":false,"visible":false},{"text":"MRI cervical spines","correct":false,"visible":false},{"text":"CT brain","correct":false,"visible":false}]},{"id":13237,"text":"A 20-year-old male presented to the neurology outpatient department with complaints of bilateral lower limb weakness and urinary incontinence for the last 4 days. On examination, he had decreased power in both lower limbs with increased tone, brisk reflex, and upgoing plantar. The sensory level was found at the xiphisternum. What is the most likely neurological localization in this case?","explanation":"The clinical presentation of bilateral lower limb weakness, urinary incontinence, brisk reflexes, and an upgoing plantar reflex, along with a sensory level at the xiphisternum, strongly suggests a lesion within the **spinal cord.** This constellation of findings is indicative of an upper motor neuron lesion.\r\n\r\nThe xiphisternum, which corresponds to the T7-T8 vertebral level, is significant in this context. Below this level, the spinal cord predominantly contains nerve fibers that contribute to the lumbar and sacral spinal nerves, responsible for innervating the lower limbs and controlling bladder function. Therefore, a lesion at or above the T7-T8 level can result in the observed neurological deficits.\r\n\r\nWhile peripheral nerve, anterior horn cell, and brainstem lesions can also cause weakness and neurological symptoms, the sensory level at the xiphisternum points specifically to a spinal cord pathology as the primary cause of the patient's symptoms.","reference":"(1) Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 166.\r\n(2) Dow Lecture Slides. Neuroscience Module. Subject: Neurology, Topic: Investigations of Neurological Disorders, Sub-topic: Lesions Localized to Spinal Cord.","responses":[{"text":"Peripheral nerves","correct":false,"visible":false},{"text":"Brain stem","correct":false,"visible":false},{"text":"Muscles","correct":false,"visible":false},{"text":"Anterior horn cells","correct":false,"visible":false},{"text":"Spinal cord","correct":true,"visible":false}]},{"id":13245,"text":"Vitamin K reverses the overdose of which of the following agents?","explanation":"**Warfarin** is an anticoagulant medication used to prevent the formation of blood clots. It works by inhibiting the activity of vitamin K epoxide reductase, an enzyme responsible for recycling vitamin K in its active form. Vitamin K is essential for the synthesis of clotting factors in the liver. By blocking this process, Warfarin reduces the production of clotting factors, leading to anticoagulation.\r\n\r\nIn cases of Warfarin overdose or when the anticoagulant effect needs to be reversed quickly, vitamin K can be administered. Vitamin K serves as a cofactor in the production of clotting factors, helping to restore their levels and promote normal blood clotting. This reversal agent is particularly useful in situations where there is a risk of excessive bleeding due to Warfarin therapy.\r\n\r\nIt's important to note that vitamin K reversal is specific to Warfarin and doesn't affect other anticoagulants like Tirofiban, Clopidogrel, Eptifibatide, or Unfractionated heparin, each of which has its own mechanisms of action and potential antidotes or reversal agents when needed.","reference":"Katzung BG, Kruidering-Hall M, Trevor AJ. Katzung \u0026 Trevor’s Pharmacology Examination \u0026 Board Review. 12th ed. McGraw-Hill Education; 2019: 287.","responses":[{"text":"Warfarin","correct":true,"visible":false},{"text":"Unfractionated heparin","correct":false,"visible":false},{"text":"Clopidogrel","correct":false,"visible":false},{"text":"Eptifibatide","correct":false,"visible":false},{"text":"Tirofiban","correct":false,"visible":false}]},{"id":13247,"text":"What is the major advantage of magnetic resonance imaging (MRI) over computed tomography (CT) scan?","explanation":"The major advantage of magnetic resonance imaging (MRI) over computed tomography (CT) scan lies in its **excellent soft tissue imaging with high contrast sensitivity**.\r\n\r\nMRI is a powerful diagnostic tool that provides exceptionally detailed images of soft tissues within the body. It uses a strong magnetic field and radio waves to create images, and it excels at distinguishing between different types of soft tissues, such as muscles, organs, and the brain, with remarkable clarity. This high contrast sensitivity allows healthcare professionals to visualize subtle structural and pathological changes that may not be as clearly visible with a CT scan.\r\n\r\nIn contrast, CT scans primarily rely on X-ray technology, which is better suited for visualizing denser materials like bones and calcified lesions. \r\n\r\nFurthermore, MRI does not use ionizing radiation, making it a safer option for repeated or prolonged imaging, particularly in cases involving pregnant individuals or pediatric patients.","reference":"Dow Lecture Slides. Reproductive Module. Subject: Radiology, Topic: CT and MRI of Spinal Cord, Sub-topic: MRI Introduction.","responses":[{"text":"Quick modality","correct":false,"visible":false},{"text":"Does not require any prior preparation","correct":false,"visible":false},{"text":"Superior in detection of calcified lesions","correct":false,"visible":false},{"text":"Use of ionization radiation","correct":false,"visible":false},{"text":"Excellent soft tissue imaging with high contrast sensitivity","correct":true,"visible":false}]},{"id":14350,"text":"A 35-year-old housewife presents to the neurology clinic for evaluation of persistent headache and vomiting for one week with intermittent clouding of consciousness and confusion. She had a prior history of weight loss and fever for the past two months. Two years back, she was treated for pulmonary tuberculosis and became asymptomatic. On examination, signs of meningeal irritation are positive with bilateral papilledema. MRI brain contrast suggests central nervous system tuberculosis. Cerebrospinal fluid detailed report is awaited. What is the most appropriate next step in the management of this patient?","explanation":"The patient's history along with the clinical presentation raises strong suspicion of central nervous system tuberculosis (CNS TB). The most appropriate next step in management is to **start anti-tuberculous therapy**.\r\n\r\nCNS TB is a serious condition that requires immediate treatment. Delay in initiating therapy can lead to further neurological complications and potentially life-threatening outcomes. Anti-tuberculous therapy consists of a combination of medications such as isoniazid, rifampicin, pyrazinamide, and ethambutol, tailored to the patient's specific condition and guided by sensitivity testing once the cerebrospinal fluid (CSF) report becomes available.\r\n\r\nWhile additional investigations like an EEG and CSF analysis will provide valuable information, the urgency in managing this patient's suspected CNS TB warrants the initiation of anti-tuberculous therapy as the first step. The CSF report will help confirm the diagnosis and guide treatment adjustments if necessary.","reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 1174.","responses":[{"text":"Start anti-tuberculous therapy","correct":true,"visible":false},{"text":"Start anti-fungals","correct":false,"visible":false},{"text":"Start steroids","correct":false,"visible":false},{"text":"Wait for CSF report","correct":false,"visible":false},{"text":"Get an EEG done","correct":false,"visible":false}]},{"id":15361,"text":"A child is brought to the emergency room with complaints of severe vomiting and seizures. A radiologic scan revealed dilation of the fourth ventricle. Which of the following structures form(s) the floor of the fourth ventricle?","explanation":"The **floor of the fourth ventricle** is primarily formed by several structures, including the **posterior surface of the pons** and the **medulla oblongata**.\r\n\r\nThe **posterior surface of the pons** contributes to the upper part of the fourth ventricle's floor, while the **medulla oblongata** forms the lower part. The **superior medullary velum** and the **inferior medullary velum** are also involved in shaping the floor of the fourth ventricle. These velum structures help to cover the ventricle's upper and lower regions, respectively.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 445.","responses":[{"text":"Posterior surface of the pons and medulla","correct":true,"visible":false},{"text":"Inferior cerebellar peduncle","correct":false,"visible":false},{"text":"Superior cerebellar peduncle","correct":false,"visible":false},{"text":"Anterior surface of cerebellum","correct":false,"visible":false},{"text":"Superior and inferior medullary velum","correct":false,"visible":false}]},{"id":15362,"text":"A 55-year-old male patient presents to the neurology clinic with the complaint of not being able to acknowledge the left side of his body. He does not wash, shave, or use the left side of his body. A lesion in which of the following areas of the cerebral cortex is the most likely cause for this deficit in the patient?","explanation":"The symptoms described in the patient, characterized by an inability to acknowledge the left side of his body, suggest a lesion in the **somesthetic association area** of the cerebral cortex. This area is responsible for the complex processing and interpretation of somatosensory information, including the integration and recognition of sensations related to the position and orientation of body parts.\r\n\r\nWhen there is damage to the somesthetic association area, particularly in the right hemisphere, patients may experience **neglect syndrome,** where they fail to recognize or respond to stimuli on one side of their body (in this case, the left side). This condition is not due to a primary sensory deficit but rather a failure in the higher-order processing of sensory information.\r\n\r\nThe secondary somesthetic area processes sensory input, but its lesion typically doesn't lead to neglect syndrome; the prefrontal gyrus is involved in executive functions; the primary somesthetic area processes basic sensory information from the body; and the precentral gyrus is concerned with motor control.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 291.","responses":[{"text":"Primary somesthetic area","correct":false,"visible":false},{"text":"Prefrontal gyrus","correct":false,"visible":false},{"text":"Secondary somesthetic area","correct":false,"visible":false},{"text":"Precentral gyrus","correct":false,"visible":false},{"text":"Somesthetic association area","correct":true,"visible":false}]},{"id":15442,"text":"Which of the following conditions is associated with low levels of gamma-aminobutyric acid (GABA)?","explanation":"Gamma-aminobutyric acid, or GABA, is the primary inhibitory neurotransmitter in the central nervous system. It plays a crucial role in regulating brain activity by inhibiting or reducing the excitability of neurons. When GABA levels are low, the balance between excitatory and inhibitory neurotransmitters in the brain can be disrupted, leading to increased neuronal activity and, in some cases, **anxiety.**\r\n\r\nAnxiety disorders are often characterized by excessive worry, fear, and heightened arousal. Low GABA levels can contribute to this by failing to dampen the overactivity of neurons, resulting in a state of hyperarousal and anxiety.","reference":"Dow lecture slides. Neuroscience module. Subject: Biochemistry, Topic: Neurotransmitters, Sub-topic: GABA.","responses":[{"text":"Attention deficit hyperactivity disorder","correct":false,"visible":false},{"text":"Increased pain sensation","correct":false,"visible":false},{"text":"Cerebral palsy","correct":false,"visible":false},{"text":"Epilepsy","correct":false,"visible":false},{"text":"Anxiety","correct":true,"visible":false}]},{"id":15443,"text":"Which of the following statements distinguishes the optic nerve from the optic tract?","explanation":"The optic nerve (cranial nerve II) is responsible for carrying visual information from the retina of the eye to the brain. It consists of axons from retinal ganglion cells, and these axons do not undergo decussation (crossing over) in the optic nerve. As a result, all the **fibers in the optic nerve originate from the same side (ipsilateral) of the retina**, conveying information from one eye.\r\n\r\nOn the other hand, the optic tract, which follows the optic nerve, contains a mixture of fibers. **Some of these fibers originate from the ipsilateral eye,** carrying information from the same side of the retina, **while others are from the contralateral eye,** conveying information from the opposite side of the retina. This crossing of fibers (decussation) occurs at the optic chiasm, where a partial crossover takes place.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 327.","responses":[{"text":"Optic nerve is a part of peripheral nervous system while optic tract is a part of central nervous system","correct":false,"visible":false},{"text":"Optic nerve has only ipsilateral fibers while optic tract has only contralateral fibers","correct":false,"visible":false},{"text":"Optic nerve has Schwann cells while optic tract has oligodendrocytes","correct":false,"visible":false},{"text":"Optic nerve is unmyelinated while optic tract is myelinated","correct":false,"visible":false},{"text":"Optic nerve has only ipsilateral fibers while the optic tract has both ipsilateral and contralateral fibers","correct":true,"visible":false}]},{"id":15444,"text":"A 35-year-old man is brought to the emergency room after he suffers a head injury in a road traffic accident. It is observed that he has flailing movement in his left upper limb. Which of the following structures is the most likely site of lesion in this case?","explanation":"The **subthalamus** is a part of the diencephalon and is involved in motor control. It plays a crucial role in regulating motor functions by interacting with the basal ganglia, specifically the globus pallidus. Disruption or damage to the subthalamus can lead to dyskinesias, which are abnormal involuntary movements, including flailing or hyperkinetic movements of the limbs.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 315.","responses":[{"text":"Hypothalamus","correct":false,"visible":false},{"text":"Globus pallidus","correct":false,"visible":false},{"text":"Spinal cord","correct":false,"visible":false},{"text":"Midbrain","correct":false,"visible":false},{"text":"Subthalamus","correct":true,"visible":false}]},{"id":15445,"text":"A 42-year-old woman suffered a head injury in a road traffic accident. She was brought to the emergency room and underwent an MRI scan, which revealed a hemorrhage in the inferior frontal gyrus. Which of the following symptoms is the most likely manifestation of a lesion in this area of the cerebral cortex?","explanation":"A hemorrhage in the inferior frontal gyrus of the cerebral cortex can lead to a specific set of symptoms, with the most likely manifestation being the **inability to speak whole words**. This area of the cerebral cortex is known as **Broca's area**, and it is primarily responsible for speech production.\r\n\r\nLesions in Broca's area can result in a condition called **Broca's aphasia** or expressive aphasia. Patients with Broca's aphasia have difficulty forming complete words and sentences, and their speech may come out fragmented and laborious. They often struggle to express themselves verbally but can generally understand spoken language.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 290.","responses":[{"text":"Inability to speak whole words","correct":true,"visible":false},{"text":"Paralysis of pharynx and larynx","correct":false,"visible":false},{"text":"Paralysis of the upper limb","correct":false,"visible":false},{"text":"Deviation of the eyes to side of lesion","correct":false,"visible":false},{"text":"Inability to grasp objects with her hands","correct":false,"visible":false}]},{"id":15446,"text":"The craniosacral outflow constitutes the parasympathetic nervous system. The parasympathetic fibers of which of the following nerves control the pupillary and accommodation reflexes?","explanation":"The **oculomotor nerve** contains parasympathetic fibers that originate from the **Edinger-Westphal nucleus** in the midbrain. These fibers travel along with the oculomotor nerve to reach their target structures, which include the **pupil constrictor muscle** (sphincter pupillae) of the eye and the **ciliary muscle**. \r\n\r\nWhen light intensity changes or near vision tasks are performed, the parasympathetic fibers within the oculomotor nerve are activated. This results in the constriction of the pupil (miosis) and the adjustment of the shape of the lens (accommodation), allowing the eye to focus on close objects.","reference":"(1) Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 660.\r\n\r\n(2) Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 331.","responses":[{"text":"Facial nerve","correct":false,"visible":false},{"text":"Glossopharyngeal nerve","correct":false,"visible":false},{"text":"Hypoglossal nerve","correct":false,"visible":false},{"text":"Vagus nerve","correct":false,"visible":false},{"text":"Oculomotor nerve","correct":true,"visible":false}]},{"id":15447,"text":"A 45-year-old woman suffers from a stroke and has difficulty with speech. She can write and understand speech but is unable to produce any words. The area affected in this case is located in which of the following gyri of the cerebral cortex?","explanation":"The inability to produce words while maintaining the capacity to comprehend and write is a condition known as **Broca's aphasia**, also referred to as **expressive aphasia**. This condition typically results from damage to the **inferior frontal gyrus** of the cerebral cortex, specifically within the **left hemisphere**.\r\n\r\nPatients with Broca's aphasia often struggle with forming grammatically correct sentences and may experience difficulty with word-finding and speech fluency. However, their comprehension and ability to write are relatively intact, as these functions are primarily governed by different areas of the brain.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 290.","responses":[{"text":"Precentral gyrus","correct":false,"visible":false},{"text":"Inferior frontal gyrus","correct":true,"visible":false},{"text":"Superior temporal gyrus","correct":false,"visible":false},{"text":"Superior frontal gyrus","correct":false,"visible":false},{"text":"Middle frontal gyrus","correct":false,"visible":false}]},{"id":15455,"text":"Which of the following types of neurons innervate extrafusal muscle fibers?","explanation":"The neurons responsible for innervating **extrafusal muscle fibers**, which are the main contractile fibers in skeletal muscles, are known as **alpha motor neurons**. These neurons are a crucial component of the somatic motor system, which controls voluntary muscle movements.\r\n\r\nAlpha motor neurons are part of the larger motor unit, which includes the alpha motor neuron, the extrafusal muscle fibers it innervates, and any associated muscle spindle fibers. When these alpha motor neurons are stimulated by signals from the central nervous system, they transmit electrical impulses to the extrafusal muscle fibers, causing them to contract. This contraction is what produces muscle movement and enables voluntary control over various bodily movements.\r\n\r\nIn contrast to alpha motor neurons, **gamma motor neurons** innervate **intrafusal muscle fibers** found within muscle spindles. These intrafusal muscle fibers play a role in regulating muscle tone and providing proprioceptive feedback to the nervous system. Together, alpha and gamma motor neurons ensure coordinated and controlled muscle function.","reference":"Costanzo LS. BRS: Physiology. 7th ed. Wolters Kluwer; 2019: 50.","responses":[{"text":"Alpha motor neurons","correct":true,"visible":false},{"text":"A-delta neurons","correct":false,"visible":false},{"text":"Gamma motor neurons","correct":false,"visible":false},{"text":"C type nerve fibers","correct":false,"visible":false},{"text":"A-beta neurons","correct":false,"visible":false}]},{"id":15456,"text":"Which of the following types of nerve fibers innervate Golgi tendon organs?","explanation":"**Golgi tendon organs**, also known as **Golgi tendon receptors**, are specialized sensory receptors located at the junction of a muscle and its tendon. These organs play a crucial role in monitoring muscle tension and preventing excessive force generation during muscle contractions. To achieve this, Golgi tendon organs are innervated by **Ib sensory afferents**.\r\n\r\nThe **Ib sensory afferents** are part of the proprioceptive sensory system and serve as feedback mechanisms to monitor changes in muscle tension. When the tension in a muscle increases, such as during a strong muscle contraction, Golgi tendon organs are stimulated. This stimulation, in turn, activates the Ib sensory afferents, which send signals to the central nervous system (CNS) to modulate muscle activity.\r\n\r\nIn response to Golgi tendon organ activation, the CNS can inhibit muscle contraction, preventing excessive force that could potentially lead to muscle or tendon damage.","reference":"Costanzo LS. BRS: Physiology. 7th ed. Wolters Kluwer; 2019: 50.","responses":[{"text":"Ib sensory afferents","correct":true,"visible":false},{"text":"II sensory afferents","correct":false,"visible":false},{"text":"III sensory afferents","correct":false,"visible":false},{"text":"IV sensory afferents","correct":false,"visible":false},{"text":"Ia sensory afferents","correct":false,"visible":false}]},{"id":15457,"text":"Which of the following is an opioid receptor antagonist used as a drug for opioid overdose and toxicity?","explanation":"When a person takes opioids, whether through prescription medications like morphine or illicit substances like heroin, these drugs bind to specific receptors known as opioid receptors in the central nervous system. Activation of these receptors can result in a range of effects, including pain relief and, at higher doses, respiratory depression.\r\n\r\n**Naloxone** works by competitively binding to the same opioid receptors but without activating them. This binding rapidly reverses the effects of opioids, essentially blocking their action. As a result, naloxone can quickly restore normal breathing in individuals experiencing opioid-induced respiratory depression, potentially saving their lives.","reference":"Karen Whalen. Lippincott Illustrated Reviews: Pharmacology (South Asian Edition). (Sharma S, Velpandian T, eds.). Wolters Kluwer; 2019: 190.","responses":[{"text":"Nalbuphine","correct":false,"visible":false},{"text":"Naloxone","correct":true,"visible":false},{"text":"Buprenorphine","correct":false,"visible":false},{"text":"Morphine","correct":false,"visible":false},{"text":"Fentanyl","correct":false,"visible":false}]},{"id":15458,"text":"Which of the following neurotransmitters equally excites both alpha and beta-adrenergic receptors?","explanation":"**Epinephrine,** also known as adrenaline, is a hormone and neurotransmitter produced by the adrenal glands in response to stress or the \"fight or flight\" response. It plays a pivotal role in the body's physiological response to stress and danger.\r\n\r\nEpinephrine has a broad spectrum of effects because it binds to both alpha and beta-adrenergic receptors on target cells. These receptors are classified into subtypes, such as alpha-1, alpha-2, beta-1, and beta-2. Epinephrine's ability to activate both alpha and beta receptors allows it to produce a wide range of physiological responses, including increased heart rate and contractility (beta-1 receptor activation), bronchodilation (beta-2 receptor activation), and vasoconstriction (alpha-1 receptor activation).","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 768.","responses":[{"text":"Epinephrine","correct":true,"visible":false},{"text":"Tyrosine","correct":false,"visible":false},{"text":"Acetylcholine","correct":false,"visible":false},{"text":"Dopamine","correct":false,"visible":false},{"text":"Norepinephrine","correct":false,"visible":false}]},{"id":15459,"text":"A 55-year-old man with a history of resting tremors in his right hand dies in a road traffic accident and undergoes an autopsy. His neurological examination is likely to reveal degeneration of neurons in which of the following structures?","explanation":"The resting tremors in the right hand and the presentation of Parkinson's disease are suggestive of degeneration of dopaminergic neurons in the **left substantia nigra**. The substantia nigra is a key structure located in the midbrain, specifically in the basal ganglia. \r\n\r\nIn Parkinson's disease, there is a loss of dopaminergic neurons in the substantia nigra, particularly in the **pars compacta** region. This loss of dopaminergic neurons results in a reduction of dopamine production in the brain. Dopamine is a neurotransmitter involved in the modulation of movement and motor control.\r\n\r\nThe degeneration of neurons in the substantia nigra leads to an imbalance in the control of motor functions, resulting in the characteristic symptoms of Parkinson's disease, including resting tremors, bradykinesia (slowness of movement), rigidity, and postural instability.","reference":"Ghoneim A, Pollard C, Tyagi A, Jampana R. Substantia nigra micro-haemorrhage causing ipsilateral unilateral Parkinsonism and abnormal dopamine transporter scan uptake. BJR | Case Reports. Published October 8, 2020. Accessed March 23, 2023. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC7869125/","responses":[{"text":"Left corpus striatum","correct":false,"visible":false},{"text":"Left globus pallidus","correct":false,"visible":false},{"text":"Left substantia nigra","correct":true,"visible":false},{"text":"Right globus pallidus","correct":false,"visible":false},{"text":"Right substantia nigra","correct":false,"visible":false}]},{"id":15460,"text":"Which of the following statements correctly describes the main function of the blood-brain barrier?","explanation":"The blood-brain barrier (BBB) is a highly specialized and crucial physiological feature of the central nervous system (CNS). Its primary function is to **prevent hazardous substances from reaching the brain while supplying essential nutrients** and maintaining a stable environment for optimal neuronal function.\r\n\r\nOne of the main functions of the BBB is to act as a protective barrier. In addition to its protective role, the BBB plays a critical role in supplying the brain with essential nutrients, such as glucose and amino acids. Furthermore, the BBB also maintains a stable chemical environment within the CNS. It prevents drastic fluctuations in ion concentrations and pH, ensuring that neurons can function optimally.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 180.","responses":[{"text":"Detects changes in the chemical composition of blood","correct":false,"visible":false},{"text":"Secretes neurotransmitters","correct":false,"visible":false},{"text":"Supplies nutrition to and prevents hazardous substances from reaching the brain","correct":true,"visible":false},{"text":"Acts as a shock absorber","correct":false,"visible":false},{"text":"Secretes cerebrospinal fluid (CSF)","correct":false,"visible":false}]},{"id":15461,"text":"A child suffers from non-communicating hydrocephalus. Which of the following is a characteristic of non-communicating hydrocephalus?","explanation":"**Non-communicating hydrocephalus** is characterized by the blockage or obstruction in the flow of cerebrospinal fluid (CSF) within the brain, resulting in an accumulation of CSF in certain ventricles. Unlike communicating hydrocephalus, where there is an impaired absorption of CSF, non-communicating hydrocephalus is primarily associated with a physical obstruction.\r\n\r\nThe obstruction typically occurs at specific sites within the brain's ventricular system, and one of the classic locations is the **blockage of the cerebral aqueduct**, which connects the third and fourth ventricles. When this passage is blocked, CSF cannot flow smoothly from the third ventricle to the fourth ventricle, leading to an increase in intraventricular pressure and the accumulation of CSF within the ventricles.\r\n\r\nNon-communicating hydrocephalus can have various underlying causes, such as congenital abnormalities, tumors, infections, or structural changes in the brain.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1255.","responses":[{"text":"Post-hemorrhagic","correct":false,"visible":false},{"text":"Decreased absorption of CSF","correct":false,"visible":false},{"text":"Blockage of cerebral aqueduct","correct":true,"visible":false},{"text":"Post-infectious","correct":false,"visible":false},{"text":"Increased absorption of CSF","correct":false,"visible":false}]},{"id":15462,"text":"A 65-year-old male suffers from a cerebrovascular accident. An MRI scan reveals a lesion in the left internal capsule. Which of the following signs or symptoms is most likely to be observed in this patient?","explanation":"The internal capsule is a compact bundle of white matter fibers that serve as a major conduit for motor signals traveling between the cerebral cortex and the spinal cord. Specifically, the **pyramidal motor tracts**, which are responsible for voluntary motor control, pass through the internal capsule.\r\n\r\nWhen there is a lesion in the left internal capsule, it can disrupt the motor fibers responsible for controlling the right side of the body. This disruption often leads to **spastic paralysis**, characterized by increased muscle tone, exaggerated deep tendon reflexes, and difficulty in voluntary movements. \r\n\r\nThe **flaccid paralysis** and **hyporeflexia** typically occur in conditions affecting lower motor neurons.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 166, 269.","responses":[{"text":"Flaccid paralysis in left leg","correct":false,"visible":false},{"text":"Flaccid paralysis in right leg","correct":false,"visible":false},{"text":"Spastic paralysis in right leg","correct":true,"visible":false},{"text":"Hyporeflexia in left leg","correct":false,"visible":false},{"text":"Spastic paralysis in left leg","correct":false,"visible":false}]},{"id":15463,"text":"Which of the following opioid drugs is used to treat diarrhea?","explanation":"**Loperamide** is an antidiarrheal medication that belongs to the class of opioids. It acts on the **mu-opioid receptors** in the gastrointestinal tract. These receptors are found in the intestinal wall and play a role in regulating gut motility and reducing intestinal secretions.\r\n\r\nWhen loperamide binds to the mu-opioid receptors in the intestines, it **slows down peristalsis**, which is the rhythmic contractions of the intestines that push stool forward. By doing so, loperamide helps to increase the time stool spends in the intestines, allowing for greater absorption of water and electrolytes and resulting in **firmer stools**. This effect is particularly beneficial in cases of diarrhea, as it can reduce the frequency and urgency of bowel movements, providing relief to individuals with diarrhea.","reference":"Karen Whalen. Lippincott Illustrated Reviews: Pharmacology (South Asian Edition). (Sharma S, Velpandian T, eds.). Wolters Kluwer; 2019: 548.","responses":[{"text":"Loperamide","correct":true,"visible":false},{"text":"Levorphanol","correct":false,"visible":false},{"text":"Morphine","correct":false,"visible":false},{"text":"Naloxone","correct":false,"visible":false},{"text":"Methadone","correct":false,"visible":false}]},{"id":15464,"text":"Which of the following Brodmann's areas corresponds to the motor speech area of Broca?","explanation":"Brodmann areas are regions of the cerebral cortex that are defined based on their cytoarchitectural characteristics, meaning the arrangement and organization of cells in these areas. **Brodmann area 44**, also known as **Broca's area**, is a crucial part of the brain involved in speech production and motor control of language.\r\n\r\nDamage to Brodmann area 44 can result in a condition known as **Broca's aphasia**, which is characterized by difficulty in forming grammatically correct sentences and speech production. Individuals with Broca's aphasia often struggle to articulate words and sentences fluently, even though their comprehension of language remains relatively intact.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 284.","responses":[{"text":"Brodmann area 44","correct":true,"visible":false},{"text":"Brodmann area 7","correct":false,"visible":false},{"text":"Brodmann area 17","correct":false,"visible":false},{"text":"Brodmann area 22","correct":false,"visible":false},{"text":"Brodmann area 41","correct":false,"visible":false}]},{"id":15465,"text":"A 67-year-old male patient presents to the clinic with complaints of not being able to shrug his shoulders and move his head from side to side over the last few days. Which of the following nerves is most likely to be damaged in this case?","explanation":"The **Accessory nerve** primarily controls the **sternocleidomastoid** and **trapezius** muscles. The sternocleidomastoid muscle allows for the rotation of the head to the opposite side and the tilting of the head forward, while the trapezius muscle is responsible for shoulder shrugging and scapular movements. Damage to the Accessory nerve can result in weakness or paralysis of these muscles, leading to the observed symptoms.\r\n\r\nThe Abducens nerve controls eye movement, the Trigeminal nerve is involved in facial sensation and chewing, the Facial nerve controls facial expressions, and the Hypoglossal nerve controls tongue movements.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 353.","responses":[{"text":"Abducens nerve","correct":false,"visible":false},{"text":"Trigeminal nerve","correct":false,"visible":false},{"text":"Facial nerve","correct":false,"visible":false},{"text":"Hypoglossal nerve","correct":false,"visible":false},{"text":"Accessory nerve","correct":true,"visible":false}]},{"id":15466,"text":"Which of the following disorders is characterized by excessive daytime sleepiness and sudden loss of muscle tone?","explanation":"**Narcolepsy** is a neurological disorder that affects the brain's ability to regulate sleep-wake cycles properly. One of its hallmark symptoms is **excessive daytime sleepiness**, which means that individuals with narcolepsy can experience overwhelming and uncontrollable urges to fall asleep during the day, even in inappropriate situations. This extreme sleepiness can interfere with daily activities and lead to impaired functioning.\r\n\r\nAnother distinctive feature of narcolepsy is the occurrence of **cataplexy**, which is the sudden and temporary loss of muscle tone or muscle weakness. Cataplexy is often triggered by strong emotions such as laughter, surprise, or anger. During a cataplectic episode, a person may experience muscle weakness or even collapse, but they remain fully conscious.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 755.","responses":[{"text":"Epilepsy","correct":false,"visible":false},{"text":"Somnolence","correct":false,"visible":false},{"text":"Cataplexy","correct":false,"visible":false},{"text":"Alzheimer's disease","correct":false,"visible":false},{"text":"Narcolepsy","correct":true,"visible":false}]},{"id":15467,"text":"Which of the following cell structures constitute the white matter of the central nervous system?","explanation":"**Axons** are the long, slender projections of nerve cells (neurons) that transmit electrical signals, known as action potentials, from one part of the nervous system to another. These axons are bundled together into tracts or pathways, forming the white matter of the CNS. Their white appearance is due to the presence of myelin, a fatty substance that surrounds and insulates many axons, facilitating rapid transmission of nerve impulses.\r\n\r\n**Glial cells**, particularly oligodendrocytes in the CNS, play a crucial role in the formation of myelin. Oligodendrocytes wrap around axons, creating the myelin sheath that covers and insulates them. This myelin sheath is essential for the efficient conduction of nerve signals and is a defining characteristic of the white matter.","reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 175.","responses":[{"text":"Cell bodies only","correct":false,"visible":false},{"text":"Axons and dendrites","correct":false,"visible":false},{"text":"Cell bodies and dendrites","correct":false,"visible":false},{"text":"Axons only","correct":false,"visible":false},{"text":"Axons and glial cells","correct":true,"visible":false}]},{"id":15468,"text":"Which of the following terms correctly describes the diphtheria toxin?","explanation":"**Exotoxins** are toxic substances secreted and released by certain bacteria as part of their metabolic processes. These toxins can be extremely potent and harmful to host organisms. Diphtheria toxin, produced by Corynebacterium diphtheriae, is a classic example of an exotoxin.\r\n\r\nDiphtheria toxin specifically targets and disrupts the protein synthesis machinery within host cells. It does this by modifying a host cell protein called elongation factor 2 (EF-2), which is essential for protein synthesis. Once EF-2 is modified by the toxin, it becomes inactive, leading to the inhibition of protein synthesis within the affected cell. This interference with protein synthesis can result in cell death and tissue damage, particularly in the respiratory tract, which is a hallmark of diphtheria infection.","reference":"Dow lecture slides. Neurosciences module. Subject: Community Medicine, Topic: Endemic diseases involving the nervous system, Sub-topic: Diphtheria.","responses":[{"text":"Exotoxin","correct":true,"visible":false},{"text":"Neurotoxin","correct":false,"visible":false},{"text":"Endotoxin","correct":false,"visible":false},{"text":"Enterotoxin","correct":false,"visible":false},{"text":"Cytotoxin","correct":false,"visible":false}]},{"id":15469,"text":"Which of the following is the most appropriate intervention after a child has been diagnosed with paralytic poliomyelitis?","explanation":"Poliomyelitis, commonly known as polio, is caused by the poliovirus and can lead to muscle weakness and paralysis, particularly in the limbs. When a child is diagnosed with paralytic poliomyelitis, their immediate and long-term care should focus on **rehabilitation** to improve their functional abilities and quality of life.\r\n\r\nRehabilitation programs for children with paralytic polio typically include physical therapy, occupational therapy, and sometimes speech therapy, depending on the extent of the paralysis and associated complications. Physical therapy helps restore muscle strength, flexibility, and mobility. Occupational therapy focuses on developing daily living skills, and speech therapy may be necessary if the muscles involved in speech have been affected.\r\n\r\nAdditionally, assistive devices such as braces, crutches, or wheelchairs may be provided to aid in mobility and independence. The goal of rehabilitation is to maximize the child's physical abilities and promote their overall well-being.","reference":"Mehndiratta MM, Mehndiratta P, Pande R. Poliomyelitis. The Neurohospitalist. Published October 2014. Accessed March 24, 2023. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4212416/","responses":[{"text":"Awareness","correct":false,"visible":false},{"text":"Vaccination","correct":false,"visible":false},{"text":"Nutritional supplementation","correct":false,"visible":false},{"text":"Rehabilitation","correct":true,"visible":false},{"text":"Health education","correct":false,"visible":false}]},{"id":15470,"text":"While operating on the pituitary gland, a surgeon tries to secure the optic chiasma. Which of the following structures separates the pituitary gland from the optic chiasm?","explanation":"The **diaphragma sellae** is a fold of dura mater, the tough outermost layer of the meninges, which are the protective coverings of the brain and spinal cord. It forms a partial roof over the sella turcica, a saddle-shaped depression in the sphenoid bone where the pituitary gland is located.\r\n\r\nThe optic chiasm, on the other hand, is a critical structure located just above the diaphragma sellae. It is the point at which the optic nerves from both eyes come together and partially cross over to the opposite side of the brain.","reference":"Moore KL, Agur AMR, Dalley AF. Clinically Oriented Anatomy. 8th ed. Wolters Kluwer; 2018: 883-884.","responses":[{"text":"Diaphragmatic sellae","correct":true,"visible":false},{"text":"Dorsum sellae","correct":false,"visible":false},{"text":"Tuberculum sellae","correct":false,"visible":false},{"text":"Cavernous sinus","correct":false,"visible":false},{"text":"Sphenoidal sinus","correct":false,"visible":false}]},{"id":15471,"text":"Which part of the nervous system consists of two ganglionated nerve trunks extending the entire length of the vertebral column on both sides?","explanation":"The part of the nervous system that consists of two ganglionated nerve trunks extending The **sympathetic nervous system** is one of the two main divisions of the autonomic nervous system, the other being the parasympathetic nervous system. It plays a crucial role in the body's \"fight or flight\" response, which is activated in situations of stress, danger, or when the body needs to prepare for heightened physical activity. \r\n\r\nThe sympathetic nervous system is characterized by the presence of these two long chains of ganglia, known as the sympathetic chain or sympathetic trunk, which run parallel to the vertebral column. These ganglia are interconnected by nerve fibers and serve as relay points for sympathetic nerve signals. When activated, the sympathetic system causes various physiological responses, such as increased heart rate, dilation of airways, and mobilization of energy reserves, to prepare the body for action.\r\n\r\nThe parasympathetic nervous system is responsible for the \"rest and digest\" response, promoting relaxation and energy conservation.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 390.","responses":[{"text":"Sympathetic nervous system","correct":true,"visible":false},{"text":"Parasympathetic nervous system","correct":false,"visible":false},{"text":"Somatic nervous system","correct":false,"visible":false},{"text":"Enteric nervous system","correct":false,"visible":false},{"text":"Autonomic nervous system","correct":false,"visible":false}]},{"id":15472,"text":"Which of the following structures connects Wernicke's area to Broca's area?","explanation":"The structure that connects Wernicke's area to Broca's area is the **arcuate fasciculus**. \r\n\r\n**Wernicke's area**, located in the posterior part of the left superior temporal gyrus, is primarily responsible for the comprehension of spoken and written language. When damaged, it can result in receptive aphasia, where the individual may produce fluent speech but struggles to understand the meaning of words.\r\n\r\n**Broca's area**, on the other hand, is situated in the posterior part of the left frontal gyrus and is associated with the production of speech. Damage to Broca's area can lead to expressive aphasia, where the individual has difficulty in forming grammatically correct sentences and may produce speech that is laborious and non-fluent.\r\n\r\nThe **arcuate fasciculus** serves as a neural pathway that connects these two critical language centers. It enables the transfer of information from Wernicke's area, where language comprehension occurs, to Broca's area, where language production takes place.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 287.","responses":[{"text":"Internal capsule","correct":false,"visible":false},{"text":"Habenular commissure","correct":false,"visible":false},{"text":"Anterior commissure","correct":false,"visible":false},{"text":"Arcuate fasciculus","correct":true,"visible":false},{"text":"Posterior commissure","correct":false,"visible":false}]},{"id":15493,"text":"A 56-year-old woman presents to the outpatient clinic with the complaint of not being able to understand spoken language. She can, however, interpret written symbols and speech. Which of the following areas of the cerebral cortex is most likely to be damaged in this case?","explanation":"In this case, the most likely area of damage is the **secondary auditory area**. This region is located in the cortex posterior to the primary auditory area, situated in the lateral sulcus and the superior temporal gyrus. Lesions affecting the secondary auditory area can result in a condition known as **word deafness** or **acoustic verbal agnosia**.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 290-291.","responses":[{"text":"Wernicke's area","correct":false,"visible":false},{"text":"Secondary auditory area","correct":true,"visible":false},{"text":"Primary visual area","correct":false,"visible":false},{"text":"Primary auditory area","correct":false,"visible":false},{"text":"Secondary visual area","correct":false,"visible":false}]},{"id":15494,"text":"Which of the following is an active efflux transporter in the blood-brain barrier?","explanation":"**P-glycoprotein** plays a crucial role in the BBB's protective function by actively transporting a wide range of substances out of the brain and back into the blood. This transporter is particularly important for the efflux of drugs and other potentially harmful compounds, contributing to the BBB's selective permeability and the brain's overall defense mechanism.\r\n\r\nThe other transporters listed, such as SGLT-2, GLUT-3, GLUT-1, and GLUT-4, are involved in glucose transport but have different roles and locations. GLUT-1 is particularly notable in the context of the BBB as it is responsible for the facilitated diffusion of glucose into the brain, but it is not an active efflux transporter. GLUT-3 and GLUT-4 also play roles in glucose transport in other tissues. SGLT-2 is primarily involved in glucose reabsorption in the kidneys.","reference":"Löscher W, Potschka H. Blood-brain barrier active efflux transporters: atp-binding cassette gene family. NeuroRx. Published January 2005. Accessed March 26, 2023. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC539326/","responses":[{"text":"GLUT-1","correct":false,"visible":false},{"text":"GLUT-3","correct":false,"visible":false},{"text":"P-glycoprotein","correct":true,"visible":false},{"text":"GLUT-4","correct":false,"visible":false},{"text":"SGLT-2","correct":false,"visible":false}]},{"id":15495,"text":"Heparin binds to which of the following molecules to produce its anti-coagulant effect?","explanation":"**Anti-thrombin III** is a natural anticoagulant protein found in the blood that plays a crucial role in regulating the coagulation cascade. Heparin enhances the activity of ATIII by binding to it. This binding accelerates the inhibitory action of ATIII on several coagulation factors, particularly thrombin (Factor IIa) and factor Xa. Thrombin is a pivotal enzyme in the coagulation pathway responsible for converting soluble fibrinogen into insoluble strands of fibrin, leading to clot formation. Factor Xa is involved in the formation of thrombin.\r\n\r\nBy enhancing the inhibitory action of ATIII on these coagulation factors, heparin effectively slows down the coagulation process. This results in the prevention of excessive blood clot formation within blood vessels, making heparin an essential medication for preventing and treating conditions associated with abnormal blood clotting, such as deep vein thrombosis, pulmonary embolism, and during certain surgical procedures.","reference":"Karen Whalen. Lippincott Illustrated Reviews: Pharmacology (South Asian Edition). (Sharma S, Velpandian T, eds.). Wolters Kluwer; 2019: 276.","responses":[{"text":"Protein C","correct":false,"visible":false},{"text":"Anti-thrombin III","correct":true,"visible":false},{"text":"Vitamin K","correct":false,"visible":false},{"text":"Von Willebrand factor","correct":false,"visible":false},{"text":"Fibrinogen","correct":false,"visible":false}]},{"id":15496,"text":"A 55-year-old woman presents to the emergency room with a head injury following a road traffic accident. MRI scans reveal damage to the periaqueductal gray area of the midbrain. A lesion in this area is most likely to result in which of the following signs or symptoms?","explanation":"Damage to the peri-aqueductal gray area of the midbrain results in the **loss of endogenous pain suppression**.\r\n\r\nThe peri-aqueductal gray (PAG) is a region in the midbrain known for its role in modulating pain perception. It contains a network of neurons that can produce powerful pain-relieving effects when activated. These neurons are involved in the body's natural pain control system, contributing to the reduction of pain perception and response during stressful or painful situations.\r\n\r\nStimulation of the PAG can lead to the release of endogenous opioids, such as endorphins, which act on opioid receptors in the brain and spinal cord to suppress pain signals. This mechanism is important for both acute and chronic pain management.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 616-617.","responses":[{"text":"Increased daytime drowsiness","correct":false,"visible":false},{"text":"Increased alertness and consciousness","correct":false,"visible":false},{"text":"Loss of endogenous pain suppression","correct":true,"visible":false},{"text":"Loss of conscious control of respiration from cerebral cortex","correct":false,"visible":false},{"text":"Loss of coordination in the movement of the head and neck","correct":false,"visible":false}]},{"id":15497,"text":"Which of the following parts of the cerebellum is involved in planning and coordinating movements?","explanation":"The **lateral zone** is especially important for the planning and coordination of movements. The **dentate nucleus** serves as an essential relay station within the cerebellum, facilitating communication between different parts of the cerebellum and other brain regions involved in motor planning and execution. When there is damage or dysfunction in the lateral zone and its associated dentate nucleus, it can lead to impaired coordination, balance, and motor planning, resulting in movement disorders and difficulties.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 712, 714.","responses":[{"text":"Lateral zone and dentate nucleus","correct":true,"visible":false},{"text":"Intermediate zone and interposed nuclei","correct":false,"visible":false},{"text":"Vermis and interposed nuclei","correct":false,"visible":false},{"text":"Vermis and fastigial nucleus","correct":false,"visible":false},{"text":"Lateral zone and fastigial nucleus","correct":false,"visible":false}]},{"id":15498,"text":"A child is born with agenesis of the corpus callosum which is a major commissural fiber. Which of the following findings is most likely to be seen in radiological scans of this child's brain?","explanation":"When examining radiological scans of a child's brain with agenesis of the corpus callosum, one of the hallmark findings is **deformed lateral ventricles**, often described as having a \"bat-wing\" deformity. \r\n\r\nThis distinctive appearance of the lateral ventricles results from the absence of the corpus callosum, a structure that plays a crucial role in supporting the shape and structure of the ventricles. In the absence of this major commissural fiber bundle, the lateral ventricles take on this unique configuration.","reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1257.","responses":[{"text":"Deformed tapetum","correct":false,"visible":false},{"text":"Deformed internal capsule","correct":false,"visible":false},{"text":"Prominent forceps minor","correct":false,"visible":false},{"text":"Deformed lateral ventricles","correct":true,"visible":false},{"text":"Prominent forceps major","correct":false,"visible":false}]},{"id":15591,"text":"A 55-year-old man presents to the neurology clinic with the complaint of right-sided weakness of the body and left-sided weakness of the face with the tongue deviating to the left upon protrusion. Which of the following structures is most likely to be affected in this case?","explanation":"The symptoms described are indicative of a neurological condition known as **medial medullary syndrome**. \r\n\r\nWithin the medulla, there is a specific region known as the **pyramidal decussation**, where the corticospinal fibers (motor fibers that control voluntary movements of the body) cross over from one side of the brain to the opposite side of the spinal cord. In this syndrome, a lesion or injury to the medulla, specifically the medial aspect, can disrupt the corticospinal tract, causing weakness on one side of the body opposite to the side of the lesion. In this case, the right-sided weakness of the body is due to a lesion on the left side of the medulla.\r\n\r\nAdditionally, the deviation of the tongue to the left upon protrusion is a result of the involvement of the hypoglossal nerve (cranial nerve XII), which exits the medulla and controls the movements of the tongue. Damage to the left side of the medulla affects the function of the left hypoglossal nerve, leading to the tongue deviation.","reference":"Splittgerber R, Snell RS. Snell’s Clinical Neuroanatomy. 8th ed. Wolters Kluwer; 2019: 215.","responses":[{"text":"Pons","correct":false,"visible":false},{"text":"Midbrain","correct":false,"visible":false},{"text":"Cerebellum","correct":false,"visible":false},{"text":"Cerebral cortex","correct":false,"visible":false},{"text":"Medulla","correct":true,"visible":false}]}
]

export default a